3927→        private void SerialCell_DataReceived(object sender, SerialDataReceivedEventArgs e)
3928→        {
3929→            var sp = sender as SerialPort;
3930→            if (sp == null) return;
3931→            try
3932→            {
3933→                string response = sp.ReadExisting();
3934→                if (string.IsNullOrWhiteSpace(response)) return;
3935→
3936→                // 각 포트별 버퍼를 따로 유지                
3937→                if (sp == SerialLeverTq1) bufferLeverTq1.Append(response);
3938→                else if (sp == SerialLeverTq2) bufferLeverTq2.Append(response);
3939→                else if (sp == SerialReclTq1) { bufferReclTq1.Append(response); _lastReclTq1Rx = DateTime.Now; }
3940→                else if (sp == SerialReclTq2) { bufferReclTq2.Append(response); _lastReclTq2Rx = DateTime.Now; }
3941→
3942→                // 포트별로 파싱
3943→                if (sp == SerialLeverTq1) ParseBuffer(sp, bufferLeverTq1, 0);
3944→                else if (sp == SerialLeverTq2) ParseBuffer(sp, bufferLeverTq2, 1);
3945→                else if (sp == SerialReclTq1) ParseBuffer(sp, bufferReclTq1, 2);
3946→                else if (sp == SerialReclTq2) ParseBuffer(sp, bufferReclTq2, 3);
3947→            }
3948→            catch (Exception ex)
3949→            {
3950→                this.Invoke((MethodInvoker)(() =>
3951→                    Logger.LogOnce("시리얼 수신 오류", $"[{sp.PortName}] 수신 오류: {ex.Message}")));
3952→            }
3953→        }
3954→        private void ParseBuffer(SerialPort sp, StringBuilder buffer, int portIndex)
3955→        {
3956→            string raw = buffer.ToString();
3957→            int startIdx = raw.IndexOf((char)0x02); // STX
3958→            int endIdx = raw.IndexOf((char)0x03);   // ETX
3959→
3960→            if (startIdx >= 0 && endIdx > startIdx)
3961→            {
3962→                string packet = raw.Substring(startIdx + 1, endIdx - startIdx - 1); // STX~ETX 제외
3963→                string valueStr = packet.Substring(1).Trim(); // 첫 문자 제외하고 숫자                
3964→                string cleaned = valueStr.Replace(" ", ""); // → "+0.0
3965→                if (double.TryParse(cleaned, out double val))
3966→                {
3967→                    this.Invoke((MethodInvoker)(() =>
3968→                    {
3969→                        switch (portIndex)
3970→                        {
3971→                            case 0:
3972→                                MeasureData1.ValueLeverTq = Math.Abs(val) * MeasureData1.ValueLeverTqTol;
3973→                                lbLeverTq1.Text = $"{MeasureData1.ValueLeverTq:F1}";
3974→                                break;
3975→                            case 1:
3976→                                MeasureData2.ValueLeverTq = Math.Abs(val) * MeasureData2.ValueLeverTqTol;
3977→                                lbLeverTq2.Text = $"{MeasureData2.ValueLeverTq:F1}";
3978→                                break;
3979→                            case 2:
3980→                                MeasureData1.ValueReclTq = (val) * MeasureData1.ValueReclTqTol;
3981→                                lbReclTq1.Text = $"{MeasureData1.ValueReclTq:F1}";
3982→                                _lastReclTq1Parse = DateTime.Now;
3983→                                _reclTq1WarningSent = false;
3984→                                _reclTq1RetryCount = 0;
3985→                                break;
3986→                            case 3:
3987→                                MeasureData2.ValueReclTq = (val) * MeasureData2.ValueReclTqTol;
3988→                                lbReclTq2.Text = $"{MeasureData2.ValueReclTq:F1}";
3989→                                _lastReclTq2Parse = DateTime.Now;
3990→                                _reclTq2WarningSent = false;
3991→                                _reclTq2RetryCount = 0;
3992→                                break;
3993→                        }
3994→                    }));
3995→                }
3996→                else
3997→                {
3998→                    // ReclTq: TryParse 실패 — 진단 로그 및 재시도
3999→                    if (portIndex == 2)
4000→                    {
4001→                        Logger.LogOnce("[토크진단]ReclTq1 파싱실패", $"[토크진단] ReclTq1 파싱실패: '{valueStr}'");
4002→                        if (_reclTq1RetryCount < 3)
4003→                        {
4004→                            _reclTq1RetryCount++;
4005→                            try { if (SerialReclTq1.IsOpen) SerialReclTq1.Write("1R"); } catch { }
4006→                            if (_reclTq1RetryCount >= 3)
4007→                                Logger.Log("[토크진단] ReclTq1 3회 재시도 후 실패 — 연결 불가로 간주");
4008→                        }
4009→                    }
4010→                    else if (portIndex == 3)
4011→                    {
4012→                        Logger.LogOnce("[토크진단]ReclTq2 파싱실패", $"[토크진단] ReclTq2 파싱실패: '{valueStr}'");
4013→                        if (_reclTq2RetryCount < 3)
4014→                        {
4015→                            _reclTq2RetryCount++;
4016→                            try { if (SerialReclTq2.IsOpen) SerialReclTq2.Write("1R"); } catch { }
4017→                            if (_reclTq2RetryCount >= 3)
4018→                                Logger.Log("[토크진단] ReclTq2 3회 재시도 후 실패 — 연결 불가로 간주");
4019→                        }
4020→                    }
4021→                }
4022→                //남은 데이터 보존
4023→                raw = raw.Substring(endIdx + 1);
4024→                buffer.Clear();
4025→                buffer.Append(raw);
4026→            }
4027→            else
