4034→                    {
4035→                        _reclTq1RetryCount++;
4036→                        try { if (SerialReclTq1.IsOpen) SerialReclTq1.Write("1R"); } catch { }
4037→                        if (_reclTq1RetryCount >= 3)
4038→                            Logger.Log("[토크진단] ReclTq1 3회 재시도 후 실패 — 연결 불가로 간주");
4039→                    }
4040→                }
4041→                else if (portIndex == 3)
4042→                {
