4047→                        try { if (SerialReclTq2.IsOpen) SerialReclTq2.Write("1R"); } catch { }
4048→                        if (_reclTq2RetryCount >= 3)
4049→                            Logger.Log("[토크진단] ReclTq2 3회 재시도 후 실패 — 연결 불가로 간주");
4050→                    }
4051→                }
4052→            }
4053→        }
