private void PortOpen(SerialPort tControl, string tPortNumber, int tBaudRate, string portLabelName)
{
    try
    {
        if (tControl.IsOpen)
            tControl.Close();

        tControl.PortName = tPortNumber;
        tControl.BaudRate = tBaudRate;
        tControl.DataBits = 8;
        tControl.Open();
        Logger.LogOnce($"포트 OK {portLabelName}", $"{portLabelName} ({tControl.PortName}): OK");

    }
    catch (Exception)
    {
        Logger.LogOnce($"포트 NG {portLabelName}", $"{portLabelName} ({tControl.PortName}): NG");

    }

}
