        private void _FrmMain_Load(object sender, EventArgs e)
        {
            Logger.Initialize(srcTxtLog);

            if (srcLvdt1 == null || srcLvdt2 == null)
                Logger.LogOnce("[경고] srcLvdt1 또는 srcLvdt2가 null입니다. LVDT 화면 표시가 동작하지 않을 수 있습니다.");

            StyleControls();

            GlobalValues.LoadSettingsFromIni();

            PLCData1.FlagRecvAll = true;
            PLCData2.FlagRecvAll = true;

            PortOpen(SerialPlc1, GlobalValues.Plc1Port, 115200, "SerialPlc1");
            PortOpen(SerialPlc2, GlobalValues.Plc2Port, 115200, "SerialPlc2");

            SerialLvdt1.Handshake = Handshake.RequestToSendXOnXOff;
            SerialLvdt2.Handshake = Handshake.RequestToSendXOnXOff;

            InitSerial(SerialLvdt1);
            InitSerial(SerialLvdt2);

            PortOpen(SerialLvdt1, GlobalValues.Lvdt1Port, 9600, "SerialLvdt1");
            PortOpen(SerialLvdt2, GlobalValues.Lvdt2Port, 9600, "SerialLvdt2");

            SerialLvdt1.DataReceived += SerialLvdt_DataReceived;
            SerialLvdt2.DataReceived += SerialLvdt_DataReceived;

            PortOpen(SerialScanner, GlobalValues.ScannerPort, 9600, "SerialScanner");
            PortOpen(SerialPrinter, GlobalValues.PrinterPort, 9600, "SerialPrinter");

            PortOpen(SerialLeverTq1, GlobalValues.LeverTq1Port, 38400, "SerialLeverTq1");
            PortOpen(SerialLeverTq2, GlobalValues.LeverTq2Port, 38400, "SerialLeverTq2");

            PortOpen(SerialReclTq1, GlobalValues.ReclTq1Port, 38400, "SerialReclTq1");
            PortOpen(SerialReclTq2, GlobalValues.ReclTq2Port, 38400, "SerialReclTq2");

            SerialLeverTq1.DataReceived += SerialCell_DataReceived;
            SerialLeverTq2.DataReceived += SerialCell_DataReceived;
            SerialReclTq1.DataReceived += SerialCell_DataReceived;
            SerialReclTq2.DataReceived += SerialCell_DataReceived;

            requestTimer = new System.Windows.Forms.Timer();
            requestTimer.Interval = 50;
            requestTimer.Tick += SerialRetryTimer_Tick;
            requestTimer.Start();

