            InitControl();

            PLCData1.SetPlcBit(9, 3, true); //알람 리셋
            PLCData1.SetPlcBit(9, 5, true); //서보 자동 ON
            PLCData1.SetPlcBit(9, 6, false); //서보 수동 OFF
            PLCData1.SetPlcBit(9, 9, true); //서보 온

            PLCData1.SetPlcBit(11, 3, true); //알람 리셋
            PLCData1.SetPlcBit(11, 5, true); //서보 자동 ON
            PLCData1.SetPlcBit(11, 6, false); //서보 수동 OFF
            PLCData1.SetPlcBit(11, 9, true); //서보 온

            PLCData2.SetPlcBit(9, 3, true); //알람 리셋
            PLCData2.SetPlcBit(9, 5, true); //서보 자동 ON
            PLCData2.SetPlcBit(9, 6, false); //서보 수동 OFF
            PLCData2.SetPlcBit(9, 9, true); //서보 온

            PLCData2.SetPlcBit(11, 3, true); //알람 리셋
            PLCData2.SetPlcBit(11, 5, true); //서보 자동 ON
            PLCData2.SetPlcBit(11, 6, false); //서보 수동 OFF
            PLCData2.SetPlcBit(11, 9, true); //서보 온

            Thread.Sleep(1000);

            PLCData1.SetPlcBit(9, 3, false); //알람 리셋
            PLCData1.SetPlcBit(11, 3, false); //알람 리셋

            PLCData2.SetPlcBit(9, 3, false); //알람 리셋
            PLCData2.SetPlcBit(11, 3, false); //알람 리셋

            PLCData1.SetPlc(5002, PLCData1.Servo1JogSpd);
            PLCData1.SetPlc(5004, PLCData1.Servo1JogSpd);
            PLCData1.SetPlc(5008, PLCData1.Servo2JogSpd);
            PLCData1.SetPlc(5010, PLCData1.Servo2JogSpd);
            PLCData1.ServoSet();

            PLCData2.SetPlc(5002, PLCData2.Servo1JogSpd);
            PLCData2.SetPlc(5004, PLCData2.Servo1JogSpd);
            PLCData2.SetPlc(5008, PLCData2.Servo2JogSpd);
            PLCData2.SetPlc(5010, PLCData2.Servo2JogSpd);
            PLCData2.ServoSet();

            InitControl1();
            InitControl2();

            workTimer1 = new System.Windows.Forms.Timer();
            workTimer1.Interval = 100;
            workTimer1.Tick += workTimer1_Tick;
            workTimer1.Start();

            workTimer2 = new System.Windows.Forms.Timer();
            workTimer2.Interval = 100;
            workTimer2.Tick += workTimer2_Tick;
            workTimer2.Start();

            StartRecallPolling();

        }
