                            PLCData1.SetPlcBit(9, 3, true); //1축 알람 리셋
                            PLCData1.SetPlcBit(11, 3, true); //2축 알람 리셋
                            tmrWatch1.Restart();
                            wStep1++;
                        }
                    }
                    else
                    {
                        wStep1 = 32;
                    }
                    break;

                case 30: // 서보 알람 뜨면
                    if (tmrWatch1.ElapsedMilliseconds > 1000)
                    {
                        tmrWatch1.Stop();
                        PLCData1.SetPlcBit(9, 3, false); //1축 알람 리셋
                        PLCData1.SetPlcBit(11, 3, false); //2축 알람 리셋
                        wStep1++;
                    }
                    break;

                case 31:
                    if (PLCData1.PlcValueBit[8, 1] == false && PLCData1.PlcValueBit[10, 1] == false)
                    {
                        _alarmRetryCount1 = 0; // 복구 성공 시 재시도 카운트 리셋
                        wStep1++;
                    }
                    else
                    {
                        if (_alarmRetryCount1 > 3)
                        {
                            Logger.LogOnce("[1] 서보 알람 3회 초과", "[1] 서보 알람 3회 초과 — step 29(유격 측정 중 서보 알람)에서 정지. 설비 점검 필요.");
                            wStep1 = 99;
                        }
                        else
                            wStep1 = 29;
                    }
                    break;

                case 32:
                    timeList1.Clear();
                    valueList1.Clear();
                    PLCData1.SetPlcBit(9, 5, false); //1축 자동 OFF
                    PLCData1.SetPlcBit(11, 5, false); //2축 자동 OFF
                    PLCData1.SetPlcBit(9, 6, true); //1축 수동 ON
                    PLCData1.SetPlcBit(11, 6, true); //2축 수동 ON
                    wStep1++;
                    break;

                case 33:
                    if (PLCData1.PlcValueBit[8, 4] == true && PLCData1.PlcValueBit[10, 4] == true) //수동 확인
                    {
                        wStep1++;
                    }
                    break;

                case 34:

                    WriteDiffLog1(34, "CW_START"); // CW 시작 로그
                    tmpNum1 = MeasureData1.DiffTorqueCorrection; // 유격 토크 보정계수 (전/후진 통합)
                    diff1CwStartLvdt = MeasureData1.ValueLvdt; // 방안2: CW 시작 시점 LVDT 저장
                    WriteDebugLog1(34, "CW_START", diff1LastX, diff1LastY);
                    if (diff1HasFirstPoint) ClassZedGraph.DrawGraphLine(PlotDiff1, diff1LastX, diff1LastY, 1);
                    PLCData1.SetPlcBit(9, 1, true); //1축 CW ON
                    WriteDiffLog1(34, "PLC_CW_ON");
                    MaxDiffFwd1 = 0; // CW(전진) 최대 변위 초기화
                    wStep1 = 34.1;
                    break;

                case 34.1:
                    {
                        // 매 타이머마다 빨강 선 그리기 (토크 방향 전환 구간 곡선 표현)
                        // 방안2: CCW 끝점에서 이어지도록 X 좌표 계산
                        // X = diff1BlackEndX + (현재LVDT - CW시작LVDT)
                        double yVal341 = tmpNum1 * MeasureData1.ValueReclTq;
                        // Y값이 범위를 넘으면 범위 내로 클램핑 (보정)
                        double yMax341 = MeasureData1.DiffGraphYMax;
                        if (yVal341 > yMax341) yVal341 = yMax341;
                        else if (yVal341 < -yMax341) yVal341 = -yMax341;
                        ClassZedGraph.DrawGraphLine(PlotDiff1, diff1BlackEndX + (MeasureData1.ValueLvdt - diff1CwStartLvdt), yVal341, 1);
                        WriteDiffLog1(34.1, "TRANSITION"); // 전환 구간 로그
                        WriteDebugLog1(34.1, "TRANSITION", diff1BlackEndX + (MeasureData1.ValueLvdt - diff1CwStartLvdt), yVal341);
                    }

                    // 토크가 음수로 바뀌면 본격 측정 시작
                    if ((MeasureData1.ValueReclTq) < 0)
                    {
                        WriteDiffLog1(34.1, "TORQUE_NEGATIVE"); // 토크 음수 전환 로그

                        DiffStartTmp1_2 = MeasureData1.ValueLvdt;

                        // CW 시작점 기록 (루프 닫기용)
                        if (!diff1RedStartCaptured)
                        {
                            diff1RedStartX = MeasureData1.ValueLvdt - DiffStartTmp1_1;
                            diff1RedStartY = tmpNum1 * MeasureData1.ValueReclTq; // 상하 반전 제거
                            diff1RedStartCaptured = true;
                        }

                        tmrWatch1.Restart();
                        wStep1 = 35;
                    }
                    break;

                case 35:
                    {
                        // 방안2: CCW 끝점에서 이어지도록 X 좌표 계산
                        // X = diff1BlackEndX + (현재LVDT - CW시작LVDT)
                        double x = diff1BlackEndX + (MeasureData1.ValueLvdt - diff1CwStartLvdt); // 방안2 적용
                        double y = tmpNum1 * MeasureData1.ValueReclTq;               // Nm // 상하 반전 제거

                        // Y값이 범위를 넘으면 범위 내로 클램핑 (보정)
                        double yMax35 = MeasureData1.DiffGraphYMax;
                        double yGraph = y;
                        if (yGraph > yMax35) yGraph = yMax35;
                        else if (yGraph < -yMax35) yGraph = -yMax35;
                        ClassZedGraph.DrawGraphLine(PlotDiff1, x, yGraph, 1);
                        _csv1.Add(x, y); // CSV에는 원본값 저장

                    diff1LastX = x;
                    diff1LastY = y;

                    // 루프용 마지막 점 갱신
                    if (!diff1HasFirstPoint)
                    {
                        diff1FirstX = x;
                        diff1FirstY = y;
                        diff1HasFirstPoint = true;
                    }

                    // 최대 변위값 추적 (CW 전진)
                    double currentDiffFwd1 = Math.Abs(MeasureData1.ValueLvdt - DiffStartTmp1_2);
                    if (currentDiffFwd1 > MaxDiffFwd1)
                    {
                        MaxDiffFwd1 = currentDiffFwd1;
                    }

                    WriteDiffLog1(35, "CW_MEASURE"); // CW 측정 로그
                    WriteDebugLog1(35, "CW_MEASURE", x, yGraph);
                    Logger.LogOnce("[1][CW]", $"[1][CW][{(x).ToString()}][{(y).ToString()}]");

                    // CW 완료: 토크 > DiffLimitFwd (단, DiffLimitFwd<=0이면 SpecDiff 변위 도달 시 완료)
                    bool cwComplete1 = (MeasureData1.DiffLimitFwd > 0 && Math.Abs(MeasureData1.ValueReclTq) > MeasureData1.DiffLimitFwd)
                        || (MeasureData1.DiffLimitFwd <= 0 && currentDiffFwd1 >= MeasureData1.SpecDiff);
                    if (cwComplete1 && tmrWatch1.Elapsed.TotalSeconds > 1)
                    {
                        WriteDiffLog1(35, "CW_END"); // CW 종료 로그
                        WriteDebugLog1(35, "CW_END", diff1LastX, diff1LastY);
                        //Logger.LogOnce($"[1][CW CONDITION][{Math.Abs(MeasureData1.ValueReclTq).ToString()}]");
                        PLCData1.SetPlcBit(9, 1, false); //1축 CW OFF
                        WriteDiffLog1(35, "PLC_CW_OFF");
                        // PLCData1.SetPlcBit(9, 7, true); //1축 수동 정지 지령 - CCW 복귀 위해 주석 처리

                        if (diff1HasFirstPoint && diff1RedStartCaptured)
                        {
                            // CCW 끝점(검은 선 끝) → CW 시작점(빨간 선 시작) - 직선 연결 제거
                            // ClassZedGraph.DrawDirectLine(
                            //     PlotDiff1,
                            //     diff1BlackEndX, diff1BlackEndY,
                            //     diff1RedStartX, diff1RedStartY,
                            //     0
                            // );

                            // CW 끝점(빨간 선 끝) → CCW 시작점(검은 선 시작)
                            // 직선 연결 대신 CCW 복귀 측정으로 곡선 완성 (case 37.5~37.7)
                            // ClassZedGraph.DrawDirectLine(
                            //     PlotDiff1,
                            //     diff1LastX, diff1LastY,
                            //     diff1FirstX, diff1FirstY,
                            //     1
                            // );
                        }

                        // 유격 로그는 CCW 복귀 완료 후 닫음 (case 37.7)
                        // CloseDiffLog1();

                        tmrWatch1.Restart();
                        wStep1++;
                    }
                    }
                    break;

                case 36:
                    if (tmrWatch1.Elapsed.TotalSeconds > 1)
                    {
                        DiffFwdTmp1 = MeasureData1.ValueLvdt;
                        tmrWatch1.Stop();
                        wStep1++;
                    }
                    break;

                case 37:

                    lbFwdDiff1.Text = MaxDiffFwd1.ToString("F2"); // CW(전진) 최대 변위 표시
                    lbTotalDiff1.Text = (Double.Parse(lbBwdDiff1.Text) + Double.Parse(lbFwdDiff1.Text)).ToString("F2");

                    double tmpf, tmpb, tmps, fval, bval, sval;

                    tmpf = Math.Abs(Double.Parse(lbFwdDiff1.Text));
                    tmpb = Math.Abs(Double.Parse(lbBwdDiff1.Text));
                    tmps = Math.Abs(Double.Parse(lbTotalDiff1.Text));

                    fval = Math.Floor((tmpf / 300) * (180 / 3.14) * 100) / 100.0;
                    bval = Math.Floor((tmpb / 300) * (180 / 3.14) * 100) / 100.0;
                    sval = Math.Floor((tmps / 300) * (180 / 3.14) * 100) / 100.0;

                    lbFwdDiffMeasure1.Text = fval.ToString("F2");
                    lbBwdDiffMeasure1.Text = bval.ToString("F2");

                    WriteMeasureLabelLog1("lbFwdDiff1", $"MaxDiffFwd1(CW측정구간 최대변위 mm)", "currentDiffFwd1=Abs(ValueLvdt-DiffStartTmp1_2)", MaxDiffFwd1.ToString("F2"));
                    WriteMeasureLabelLog1("lbBwdDiff1", $"MaxDiffBwd1={MaxDiffBwd1:F4} (이미 case28에서 설정)", "CCW 최대변위 mm", lbBwdDiff1.Text);
                    WriteMeasureLabelLog1("lbFwdDiffMeasure1", $"tmpf={tmpf:F4}, 300(반경), 180/3.14(rad→deg)", "fval=Floor((tmpf/300)*(180/π)*100)/100 도(°)", fval.ToString("F2"));
                    WriteMeasureLabelLog1("lbBwdDiffMeasure1", $"tmpb={tmpb:F4}, 300, 180/3.14", "bval=Floor((tmpb/300)*(180/π)*100)/100 도(°)", bval.ToString("F2"));
                    lbTotalDiffMeasure1.Text = (fval + bval).ToString("F2");

                    JudgeAndSetLabelF2(0, MeasureData1.SpecDiff, fval + bval, lbTotalDiffMeasure1);
                    // 속도 복원은 CCW 복귀 완료 후 case 38에서 수행
                    // PLCData1.Servo1JogSpd = tmpBeforeSpeed1;
                    // PLCData1.FlagRecvAll = true;
                    // PLCData1.ServoSet();
                    WriteDiffLog1(37, $"SPEED_KEEP_DIFF: DiffSpeed={PLCData1.DiffSpeed}, CurrentSpd={PLCData1.Servo1JogSpd}");
                    WriteDebugLog1(37, $"RESULT:FwdDiff={MaxDiffFwd1:F4},BwdDiff={MaxDiffBwd1:F4},fval={fval:F4},bval={bval:F4}");
                    wStep1 = 37.1;
                    break;

                case 37.1: // 알람 확인 및 리셋 (무조건 리셋 후 진행) — 3회 재시도
                    if (_alarmRetryCount1 >= 3)
                    {
                        Logger.LogOnce("[1] 서보 알람 3회 초과", "[1] 서보 알람 3회 초과 — step 37.1(CW 완료 후 알람 리셋)에서 정지. 설비 점검 필요.");
                        CloseDiffLog1();
                        CloseDebugLog1();
                        wStep1 = 99;
                    }
                    else
                    {
                        _alarmAtStep1 = 37.1;
                        _alarmRetryCount1++;
                        WriteDiffLog1(37.1, "ALARM_CHECK");
                        PLCData1.SetPlcBit(9, 7, false); //1축 수동 정지 지령 해제
                        PLCData1.SetPlcBit(9, 3, true); //1축 알람 리셋
                        PLCData1.SetPlcBit(11, 3, true); //2축 알람 리셋
                        WriteDiffLog1(37.1, "ALARM_RESET_ON");
                        tmrWatch1.Restart();
                        wStep1 = 37.2;
                    }
                    break;

                case 37.2: // 알람 리셋 대기 (1초)
                    if (tmrWatch1.ElapsedMilliseconds > 1000)
                    {
                        tmrWatch1.Stop();
                        PLCData1.SetPlcBit(9, 3, false); //1축 알람 리셋 OFF
                        PLCData1.SetPlcBit(11, 3, false); //2축 알람 리셋 OFF
                        WriteDiffLog1(37.2, "ALARM_RESET_OFF");
                        wStep1 = 37.3;
                    }
                    break;

                case 37.3: // 알람 해제 확인
                    if (PLCData1.PlcValueBit[8, 1] == false && PLCData1.PlcValueBit[10, 1] == false)
                    {
                        _alarmRetryCount1 = 0; // 복구 성공 시 재시도 카운트 리셋
                        WriteDiffLog1(37.3, "ALARM_CLEARED");
                        tmrWatch1.Restart();
                        wStep1 = 37.4; // 딜레이 후 CCW 복귀
                    }
                    else
                    {
                        WriteDiffLog1(37.3, "ALARM_STILL_ON");
                        if (_alarmRetryCount1 >= 3)
                        {
                            Logger.LogOnce("[1] 서보 알람 3회 초과", "[1] 서보 알람 3회 초과 — step 37.1(CW 완료 후 알람 리셋)에서 정지. 설비 점검 필요.");
                            CloseDiffLog1();
                            CloseDebugLog1();
                            wStep1 = 99;
                        }
                        else
                            wStep1 = 37.1; // 알람 아직 있으면 다시 리셋
                    }
                    break;

                case 37.4: // CCW 복귀 전 딜레이 (1초 대기)
                    WriteDiffLog1(37.4, "CCW_RETURN_DELAY");
                    if (tmrWatch1.ElapsedMilliseconds > 1000)
                    {
                        WriteDiffLog1(37.4, "CCW_RETURN_DELAY_END");
                        wStep1 = 37.5;
                    }
                    break;

                case 37.5: // CCW 복귀 측정 시작 (토크 0까지)
                    WriteDiffLog1(37.5, "CCW_RETURN_START");
                    WriteDebugLog1(37.5, "CCW_RETURN_START");
                    PLCData1.SetPlcBit(9, 6, true);  // 1축 수동 ON (필수: 수동 모드에서만 CCW/CW 동작)
                    WriteDiffLog1(37.5, "PLC_MANUAL_ON");
                    PLCData1.SetPlcBit(9, 7, false); // 1축 수동 정지 지령 해제
                    WriteDiffLog1(37.5, "PLC_STOP_OFF");
                    PLCData1.SetPlcBit(9, 1, false); // 1축 CW OFF (혹시 켜져있으면 끄기)
                    WriteDiffLog1(37.5, "PLC_CW_OFF");
                    PLCData1.SetPlcBit(9, 2, true);  // 1축 CCW ON (9,2가 CCW, 9,1이 CW)
                    WriteDiffLog1(37.5, "PLC_CCW_ON");
                    // 복귀선 첫 점을 CW 마지막 좌표에 찍어서 연결
                    ClassZedGraph.DrawGraphLine(PlotDiff1, diff1LastX, diff1LastY, 2);
                    tmrWatch1.Restart();
                    wStep1 = 37.6;
                    break;

                case 37.6: // CCW 복귀 - 토크 0까지 이동
                    {
                        double xReturn = diff1BlackEndX + (MeasureData1.ValueLvdt - diff1CwStartLvdt);
                        double yReturn = tmpNum1 * MeasureData1.ValueReclTq;

                        // 토크가 음수(CW방향)일 때만 복귀 곡선 그리기
                        if (yReturn <= 0)
                        {
                            ClassZedGraph.DrawGraphLine(PlotDiff1, xReturn, yReturn, 2); // 파랑 선 (복귀)
                            diff1LastX = xReturn;
                            diff1LastY = yReturn;
                        }
                        WriteDiffLog1(37.6, "CCW_RETURN_MEASURE");
                        WriteDebugLog1(37.6, "CCW_RETURN_MEASURE", xReturn, yReturn);

                        // 토크 60 Nm 초과 시 강제 정지 (서보 과부하 방지)
                        if (Math.Abs(MeasureData1.ValueReclTq) > 60)
                        {
                            _alarmRetryCount1 = 0;
                            Logger.LogOnce("[1] CCW 복귀 중 토크 60 Nm 초과 - 강제 정지");
                            WriteDiffLog1(37.6, "CCW_RETURN_TORQUE_OVER_60");
                            WriteDebugLog1(37.6, "CCW_RETURN_TORQUE_OVER_60", xReturn, yReturn);
                            PLCData1.SetPlcBit(9, 2, false); // CCW OFF
                            PLCData1.SetPlcBit(9, 7, true);  // 수동 정지
                            CloseDiffLog1();
                            CloseDebugLog1();
                            wStep1 = 38;
                        }
                        // 토크가 0 근처에 도달하면 완료
                        else if (Math.Abs(MeasureData1.ValueReclTq) < 0.5)
                        {
                            _alarmRetryCount1 = 0; // 정상 완료 시 재시도 카운트 리셋
                            // 그래프 원점(0,0)으로 루프 닫기
                            ClassZedGraph.DrawGraphLine(PlotDiff1, 0, 0, 2);
                            WriteDiffLog1(37.6, "CCW_RETURN_END");
                            PLCData1.SetPlcBit(9, 2, false); // CCW OFF
                            WriteDiffLog1(37.6, "PLC_CCW_OFF");
                            PLCData1.SetPlcBit(9, 7, true);  // 수동 정지
                            WriteDiffLog1(37.6, "PLC_STOP_ON");
                            CloseDiffLog1();
                            CloseDebugLog1();
                            wStep1 = 38;
                        }
                        // 타임아웃: 15초 내 원점 미도달 시 강제 완료
                        else if (tmrWatch1.Elapsed.TotalSeconds > 15)
                        {
                            _alarmRetryCount1 = 0;
                            WriteDiffLog1(37.6, "CCW_RETURN_TIMEOUT");
                            WriteDebugLog1(37.6, "CCW_RETURN_TIMEOUT", xReturn, yReturn);
                            PLCData1.SetPlcBit(9, 2, false); // CCW OFF
                            PLCData1.SetPlcBit(9, 7, true);  // 수동 정지
                            CloseDiffLog1();
                            CloseDebugLog1();
                            wStep1 = 38;
                        }
                        // 서보 알람 시 자동 에러리셋 후 재시도 (최대 3회)
                        else if (PLCData1.PlcValueBit[8, 1] == true || PLCData1.PlcValueBit[10, 1] == true)
                        {
                            if (_alarmRetryCount1 >= 3)
                            {
                                Logger.LogOnce("[1] 서보 알람 3회 초과", "[1] 서보 알람 3회 초과 — step 37.6(CCW 복귀)에서 정지. 설비 점검 필요.");
                                CloseDiffLog1();
                                CloseDebugLog1();
                                wStep1 = 99;
                            }
                            else
                            {
                                _alarmAtStep1 = 37.6;
                                _alarmRetryCount1++;
                                Logger.LogOnce("[1] CCW 복귀 중 서보 알람 - 에러리셋");
                                WriteDiffLog1(37.6, "SERVO_ALARM_RESET");
                                PLCData1.SetPlcBit(9, 2, false); // CCW OFF
                                PLCData1.SetPlcBit(9, 7, false); // 수동 정지 해제
                                PLCData1.SetPlcBit(9, 3, true);  // 1축 알람 리셋
                                PLCData1.SetPlcBit(11, 3, true); // 2축 알람 리셋
                                tmrWatch1.Restart();
                                wStep1 = 37.61;
                            }
                        }
                    }
                    break;

                case 37.61: // 서보 알람 에러리셋 대기 — 알람 해제 시 진행, 최소 1초·최대 2초
                    bool alarmCleared1 = PLCData1.PlcValueBit[8, 1] == false && PLCData1.PlcValueBit[10, 1] == false;
                    bool minElapsed1 = tmrWatch1.ElapsedMilliseconds >= 1000; // 리셋 펄스 최소 1초
                    bool timeout1 = tmrWatch1.ElapsedMilliseconds > 2000;
                    if ((minElapsed1 && alarmCleared1) || timeout1)
                    {
                        if (timeout1 && !alarmCleared1)
                            Logger.LogOnce("[1] CCW 복귀 서보 알람 — 2초 내 미해제, 진행");
                        PLCData1.SetPlcBit(9, 3, false);  // 1축 알람 리셋 OFF
                        PLCData1.SetPlcBit(11, 3, false); // 2축 알람 리셋 OFF
                        PLCData1.SetPlcBit(9, 9, true);   // 1축 서보 온
                        PLCData1.SetPlcBit(11, 9, true);  // 2축 서보 온
                        CloseDiffLog1();
                        CloseDebugLog1();
                        wStep1 = 37.5; // CCW 복귀 재시도 (3회 초과 시 다음 37.6에서 99로 정지)
                    }
                    break;

                case 38:
                    // 속도 복원 (원래 속도로)
                    WriteDebugLog1(38, "MEASUREMENT_COMPLETE");
                    CloseDebugLog1(); // 디버그 로그 닫기
                    WriteDiffLog1(38, $"SPEED_RESTORE: BeforeSpeed={tmpBeforeSpeed1}, CurrentSpd={PLCData1.Servo1JogSpd}");
                    PLCData1.Servo1JogSpd = tmpBeforeSpeed1;
                    PLCData1.FlagRecvAll = true;
                    PLCData1.ServoSet();

                    PLCData1.SetPlcBit(9, 7, false); //1축 수동 정지 지령
                    PLCData1.SetPlcBit(9, 5, true); //1축 자동 ON
                    PLCData1.SetPlcBit(11, 5, true); //2축 자동 ON
                    PLCData1.SetPlcBit(9, 6, false); //1축 수동 OFF
                    PLCData1.SetPlcBit(11, 6, false); //2축 수동 OFF
                    _csv1.Save($"{tmpsave1}_Diff");
                    wStep1++;
                    break;

                case 39:
                    PLCData1.SetPlcBit(4, 12, true); //LVDT 후진 지령 D4004.12
                    wStep1++;
                    break;

                case 40:
                    if (PLCData1.PlcValueBit[0, 10] == true || PLCData1.PlcValueBit[0, 13] == true) // LVDT 후진, 가이드 후진 2
                    {
                        PLCData1.SetPlcBit(4, 12, false); //LVDT 후진 지령 D4004.12
                        PLCData1.FlagRecvAll = false;
                        wStep1++;
                    }
                    break;

                case 41:
                    if (!_lever41Delay1)
                    {
                        PLCData1.SetPlcBit(13, 1, true); //2축 2번 포지션,레버 해제
                        tmrWatch1.Restart();
                        _lever41Delay1 = true;
                    }
                    else if (tmrWatch1.ElapsedMilliseconds >= 2000)
                    {
                        _lever41Delay1 = false;
                        wStep1 = 42;
                    }
                    break;

                case 42:
                    bool complete15_1 = PLCData1.PlcValueBit[15, 1];
                    bool command13_1 = PLCData1.PlcValueBit[13, 1];
                    bool alarm8_1 = PLCData1.PlcValueBit[8, 1];
                    bool alarm10_1 = PLCData1.PlcValueBit[10, 1];
                    if (complete15_1 && command13_1) //완료 AND 명령 동시 ON
                    {
                        _alarmRetryCount1 = 0; // 레버 완료 시 재시도 카운트 리셋
                        Logger.LogOnce("[1] 레버 해제 완료");
                        PLCData1.SetPlcBit(13, 1, false); //레버 해제 완료
                        PLCData1.SetPlcBit(9, 3, true);   // 1축 에러 리셋
                        PLCData1.SetPlcBit(11, 3, true);  // 2축 에러 리셋
                        tmrWatch1.Restart();
                        wStep1 = 42.1;
                    }
                    else if (alarm8_1 || alarm10_1)
                    {
                        if (_alarmRetryCount1 >= 3)
                        {
                            Logger.LogOnce("[1] 서보 알람 3회 초과", "[1] 서보 알람 3회 초과 — step 42(레버 포지션 완료 대기)에서 정지. 설비 점검 필요.");
                            wStep1 = 99;
                        }
                        else
                        {
                            _alarmAtStep1 = 42;
                            _alarmRetryCount1++;
                            Logger.LogOnce("[1] step42 서보 알람 - 에러리셋 후 재시도");
                            PLCData1.SetPlcBit(13, 1, false);
                            PLCData1.SetPlcBit(9, 3, true);
                            PLCData1.SetPlcBit(11, 3, true);
                            tmrWatch1.Restart();
                            wStep1 = 42.1;
                        }
                    }
                    break;

                case 42.1: // 에러 리셋 후 서보 온까지 대기 (최소 1초·최대 2초)
                    bool alarmCleared42_1 = PLCData1.PlcValueBit[8, 1] == false && PLCData1.PlcValueBit[10, 1] == false;
                    bool minElapsed42_1 = tmrWatch1.ElapsedMilliseconds >= 1000;
                    bool timeout42_1 = tmrWatch1.ElapsedMilliseconds > 2000;
                    if ((minElapsed42_1 && alarmCleared42_1) || timeout42_1)
                    {
                        if (timeout42_1 && !alarmCleared42_1)
                            Logger.LogOnce("[1] step 42 에러리셋 — 2초 내 미해제, 진행");
                        PLCData1.SetPlcBit(9, 3, false);  // 1축 알람 리셋 OFF
                        PLCData1.SetPlcBit(11, 3, false); // 2축 알람 리셋 OFF
                        PLCData1.SetPlcBit(9, 9, true);   // 1축 서보 온
                        PLCData1.SetPlcBit(11, 9, true);  // 2축 서보 온
                        if (_alarmAtStep1 == 42)
                        {
                            _alarmAtStep1 = 0;
                            wStep1 = 41; // 레버 포지션 재시도
                        }
                        else
                            wStep1 = 43;
                    }
                    break;

                case 43:
                    Logger.LogOnce("[1] 1축 1번 포지션 이동 시작");
                    PLCData1.SetPlcBit(12, 0, true); //1축 1번 포지션
                    wStep1++;
                    break;

                case 44:
                    if (PLCData1.PlcValueBit[14, 0] == true && PLCData1.PlcValueBit[12, 0] == true) //완료 AND 명령 동시 ON
                    {
                        PLCData1.SetPlcBit(12, 0, false);
                        wStep1++;
                    }
                    break;

                case 45:
                    PLCData1.SetPlcBit(13, 0, true); //2축 1번 포지션,레버 원위치
                    wStep1++;
                    break;

                case 46:
                    if (PLCData1.PlcValueBit[15, 0] == true && PLCData1.PlcValueBit[13, 0] == true) //완료 AND 명령 동시 ON
                    {
                        PLCData1.SetPlcBit(13, 0, false); //레버 해제 완료
                        wStep1++;
                    }
                    break;

                case 47:

                    PLCData1.SetPlcBit(4, 8, true); //클램프 상승 지령 D4004.8
                    PLCData1.SetPlcBit(4, 10, true); //클램프 후진
                    tmrRstWatch1.Restart();
                    wStep1++;
                    break;

                case 48:
                    if (PLCData1.PlcValueBit[0, 6] == true) //클램프 상승
                    {
                        PLCData1.SetPlcBit(4, 8, false); //클램프 상승 지령 D4004.8
                    }
                    if (PLCData1.PlcValueBit[0, 9] == true) //클램프 후진 D4000.9
                    {
                        PLCData1.SetPlcBit(4, 10, false); //클램프 후진
                    }
                    if (PLCData1.PlcValueBit[0, 6] == true && PLCData1.PlcValueBit[0, 9] == true)
                    {
                        wStep1++;
                    }
                    break;

                case 49:
                    Logger.LogOnce("[1] 데이터 저장");
                    InsertData(lbBarcode1.Text, lbLPartNo1.Text,
                               lbReclFwdMeasure1.Text, CheckLabelStatus(lbReclFwdMeasure1),
                               lbReclBwdMeasure1.Text, CheckLabelStatus(lbReclBwdMeasure1),
                               lbLeverMeasure1.Text, CheckLabelStatus(lbLeverMeasure1),
                               lbFwdDiffMeasure1.Text, lbBwdDiffMeasure1.Text,
                               lbTotalDiffMeasure1.Text, CheckLabelStatus(lbTotalDiffMeasure1));
                    wStep1++;
                    break;

                case 50:

                    if (lbReclFwdMeasure1.BackColor == System.Drawing.Color.Blue &&
                        lbReclBwdMeasure1.BackColor == System.Drawing.Color.Blue &&
                        lbLeverMeasure1.BackColor == System.Drawing.Color.Blue &&
                        lbTotalDiffMeasure1.BackColor == System.Drawing.Color.Blue)
                    {
                        PlaySound("DINGDONG.wav");
                        BarcodePrint1();
                        Logger.LogOnce("[1] 바코드 출력");
                        CloseMeasureLog1();
                        GlobalValues.OkCount++;
                        GlobalValues.TotalCount++;
                        lbOkCount.Text = GlobalValues.OkCount.ToString();
                        lbNGCount.Text = (GlobalValues.TotalCount - GlobalValues.OkCount).ToString();
                        lbTotalCount.Text = GlobalValues.TotalCount.ToString();
                        GlobalValues.SaveCounts();
                    }
                    else
                    {
                        CloseMeasureLog1();
                        BarcodePrintNg1();
                        PlaySound("NG.wav");
                        GlobalValues.TotalCount++;
                        lbOkCount.Text = GlobalValues.OkCount.ToString();
                        lbNGCount.Text = (GlobalValues.TotalCount - GlobalValues.OkCount).ToString();
                        lbTotalCount.Text = GlobalValues.TotalCount.ToString();
                        GlobalValues.SaveCounts();
                    }
                    wStep1 = 51;
                    break;

                case 51:
                    if (tmrWatch1.ElapsedMilliseconds > 1000)
                    {
                        wStep1 = 0;
                        _lever41Delay1 = false;
                        _alarmRetryCount1 = 0;
                        _alarmAtStep1 = 0;
                    }
                    break;

                case 99: // 서보 알람 3회 초과 정지 — 리셋 전까지 대기
                    break;

            }

        }

        double tmpNum1, tmpNum2;

        private void workTimer2_Tick(object sender, EventArgs e)
        {
            lbStep2.Text = $"[{wStep2.ToString()}][{wRstStep2.ToString()}]";

            if (PLCData2.PlcValueBit[0, 1] == true && wRstStep2 == 0) //리셋 스위치
            {
                wRstStep2 = 0.1;
            }

            // reset
            switch (wRstStep2)
            {
                case 0:
                    break;

                case 0.1:
                    wStep2 = 0;
                    _lever41Delay2 = false;
                    _alarmRetryCount2 = 0;
                    _alarmAtStep2 = 0;
                    tmrRstWatch2.Restart();
                    wRstStep2 = 0.2;
                    break;

                case 0.2:
                    if (PLCData2.PlcValueBit[0, 1] == true)
                    {
                        if (tmrRstWatch2.ElapsedMilliseconds > 1000)
                        {
                            PLCData2.FlagRecvAll = true;
                            Logger.LogOnce("[2] 리셋 조건 발동");
                            wRstStep2 = 1;
                        }
                    }
                    else
                    {
                        wRstStep2 = 0;
                    }
                    break;

                case 1: //모든 시그널 클리어
                    for (int word = 0; word <= 7; word++)
                    {
                        for (int bit = 0; bit <= 15; bit++)
                        {
                            PLCData2.SetPlcBit(word, bit, false);
                        }
                    }
                    for (int bit = 0; bit <= 15; bit++)
                    {
                        PLCData2.SetPlcBit(9, bit, false);
                    }
                    for (int bit = 0; bit <= 15; bit++)
                    {
                        PLCData2.SetPlcBit(11, bit, false);
                    }
                    for (int bit = 0; bit <= 15; bit++)
                    {
                        PLCData2.SetPlcBit(12, bit, false);
                    }
                    for (int bit = 0; bit <= 15; bit++)
                    {
                        PLCData2.SetPlcBit(13, bit, false);
                    }
                    wRstStep2++;
                    break;

                case 2:
                    PLCData2.SetPlcBit(9, 1, false);
                    PLCData2.SetPlcBit(9, 2, false);
                    PLCData2.SetPlcBit(4, 8, true); //클램프 상승 지령 D4004.8
                    PLCData2.SetPlcBit(4, 10, true); //클램프 후진
                    PLCData2.SetPlcBit(4, 12, true); //LVDT 후진 지령 D4004.12
                    tmrWatch2.Restart();
                    wRstStep2++;
                    break;

                case 3:

                    if (PLCData2.PlcValueBit[0, 6] == true)
                    {
                        PLCData2.SetPlcBit(4, 8, false); //클램프 상승 지령 D4004.8
                    }
                    if (PLCData2.PlcValueBit[0, 9] == true)
                    {
                        PLCData2.SetPlcBit(4, 10, false); //클램프 후진 D4000.9
                    }
                    if (PLCData2.PlcValueBit[0, 10] == true)
                    {
                        PLCData2.SetPlcBit(4, 12, false); //LVDT 후진 지령 D4004.12 D4000.10
                    }

                    if (PLCData2.PlcValueBit[0, 6] == true &&
                        PLCData2.PlcValueBit[0, 9] == true &&
                        PLCData2.PlcValueBit[0, 10] == true)
                    {
                        tmrWatch2.Stop();
                        wRstStep2++;
                    }
                    break;

                case 4:
                    PLCData2.SetPlcBit(9, 9, true); //1축 서보 온
                    PLCData2.SetPlcBit(11, 9, true);//2축 서보 온
                    PLCData2.SetPlcBit(9, 3, true); //1축 알람 리셋
                    PLCData2.SetPlcBit(11, 3, true);//2축 알람 리셋
                    PLCData2.SetPlcBit(9, 6, true); //1축 수동 ON
                    PLCData2.SetPlcBit(11, 6, true);//2축 수동 ON                 
                    PLCData2.SetPlcBit(9, 5, false); //1축 자동 OFF
                    PLCData2.SetPlcBit(11, 5, false);//2축 자동 OFF                    
                    wRstStep2++;
                    break;

                case 5:
                    //신호 확인
                    if (PLCData2.PlcValueBit[8, 1] == false && PLCData2.PlcValueBit[10, 1] == false &&
                        PLCData2.PlcValueBit[8, 7] == true && PLCData2.PlcValueBit[10, 7] == true &&
                        PLCData2.PlcValueBit[8, 4] == true && PLCData2.PlcValueBit[10, 4] == true)
                    {
                        wRstStep2++;
                    }
                    break;

                case 6:

