                            _alarmAtStep2 = 29;
                            _alarmRetryCount2++;
                            PLCData2.SetPlcBit(9, 7, false); //1축 알람 리셋
                            PLCData2.SetPlcBit(9, 3, true); //1축 알람 리셋
                            PLCData2.SetPlcBit(11, 3, true); //2축 알람 리셋
                            tmrWatch2.Restart();
                            wStep2++;
                        }
                    }
                    else
                    {
                        wStep2 = 32;
                    }
                    break;

                case 30: // 서보 알람 뜨면
                    if (tmrWatch2.ElapsedMilliseconds > 1000)
                    {
                        tmrWatch2.Stop();
                        PLCData2.SetPlcBit(9, 3, false); //1축 알람 리셋
                        PLCData2.SetPlcBit(11, 3, false); //2축 알람 리셋
                        wStep2++;
                    }
                    break;

                case 31:
                    if (PLCData2.PlcValueBit[8, 1] == false && PLCData2.PlcValueBit[10, 1] == false)
                    {
                        _alarmRetryCount2 = 0; // 복구 성공 시 재시도 카운트 리셋
                        wStep2++;
                    }
                    else
                    {
                        if (_alarmRetryCount2 > 3)
                        {
                            Logger.LogOnce("[2] 서보 알람 3회 초과", "[2] 서보 알람 3회 초과 — step 29(유격 측정 중 서보 알람)에서 정지. 설비 점검 필요.");
                            wStep2 = 99;
                        }
                        else
                            wStep2 = 29;
                    }
                    break;

                case 32:
                    timeList2.Clear();
                    valueList2.Clear();
                    PLCData2.SetPlcBit(9, 5, false); //1축 자동 OFF
                    PLCData2.SetPlcBit(11, 5, false); //2축 자동 OFF
                    PLCData2.SetPlcBit(9, 6, true); //1축 수동 ON
                    PLCData2.SetPlcBit(11, 6, true); //2축 수동 ON
                    wStep2++;
                    break;

                case 33:
                    if (PLCData2.PlcValueBit[8, 4] == true && PLCData2.PlcValueBit[10, 4] == true) //수동 확인
                    {
                        wStep2++;
                    }
                    break;

                case 34:

                    WriteDiffLog2(34, "CW_START"); // CW 시작 로그
                    WriteDebugLog2(34, "CW_START", diff2LastX, diff2LastY);
                    tmpNum2 = MeasureData2.DiffTorqueCorrection; // 유격 토크 보정계수 (전/후진 통합)
                    diff2CwStartLvdt = MeasureData2.ValueLvdt; // 방안2: CW 시작 시점 LVDT 저장
                    if (diff2HasFirstPoint) ClassZedGraph.DrawGraphLine(PlotDiff2, diff2LastX, diff2LastY, 1);
                    PLCData2.SetPlcBit(9, 1, true); //1축 CW ON
                    WriteDiffLog2(34, "PLC_CW_ON");
                    MaxDiffFwd2 = 0; // CW(전진) 최대 변위 초기화
                    wStep2 = 34.1;
                    break;

                case 34.1:
                    {
                        // 매 타이머마다 빨강 선 그리기 (토크 방향 전환 구간 곡선 표현)
                        // 방안2: CCW 끝점에서 이어지도록 X 좌표 계산
                        // X = diff2BlackEndX + (현재LVDT - CW시작LVDT)
                        double yVal341_2 = tmpNum2 * -1 * (MeasureData2.ValueReclTq);
                        // Y값이 범위를 넘으면 범위 내로 클램핑 (보정)
                        double yMax341_2 = MeasureData2.DiffGraphYMax;
                        if (yVal341_2 > yMax341_2) yVal341_2 = yMax341_2;
                        else if (yVal341_2 < -yMax341_2) yVal341_2 = -yMax341_2;
                        ClassZedGraph.DrawGraphLine(PlotDiff2, diff2BlackEndX + (MeasureData2.ValueLvdt - diff2CwStartLvdt), yVal341_2, 1);
                        WriteDiffLog2(34.1, "TRANSITION"); // 전환 구간 로그
                        WriteDebugLog2(34.1, "TRANSITION", diff2BlackEndX + (MeasureData2.ValueLvdt - diff2CwStartLvdt), yVal341_2);
                    }
                    // 토크가 양수로 바뀌면 본격 측정 시작
                    if ((MeasureData2.ValueReclTq) > 0)
                    {
                        WriteDiffLog2(34.1, "TORQUE_POSITIVE"); // 토크 양수 전환 로그

                        DiffStartTmp2_2 = MeasureData2.ValueLvdt;

                        // CW 시작점 기록 (루프 닫기용)
                        if (!diff2RedStartCaptured)
                        {
                            diff2RedStartX = MeasureData2.ValueLvdt - DiffStartTmp2_1;
                            diff2RedStartY = tmpNum2 * -1 * (MeasureData2.ValueReclTq);
                            diff2RedStartCaptured = true;
                        }

                        tmrWatch2.Restart();
                        wStep2 = 35;
                    }
                    break;

                case 35:
                    {
                        // 방안2: CCW 끝점에서 이어지도록 X 좌표 계산
                        // X = diff2BlackEndX + (현재LVDT - CW시작LVDT)
                        double x = diff2BlackEndX + (MeasureData2.ValueLvdt - diff2CwStartLvdt); // 방안2 적용
                        double y = tmpNum2 * -1 * MeasureData2.ValueReclTq;               // Nm

                        // Y값이 범위를 넘으면 범위 내로 클램핑 (보정)
                        double yMax35_2 = MeasureData2.DiffGraphYMax;
                        double yGraph = y;
                        if (yGraph > yMax35_2) yGraph = yMax35_2;
                        else if (yGraph < -yMax35_2) yGraph = -yMax35_2;
                        ClassZedGraph.DrawGraphLine(PlotDiff2, x, yGraph, 1);
                        _csv2.Add(x, y); // CSV에는 원본값 저장

                        diff2LastX = x;
                    diff2LastY = y;

                    // 루프용 마지막 점 갱신
                    if (!diff2HasFirstPoint)
                    {
                        diff2FirstX = x;
                        diff2FirstY = y;
                        diff2HasFirstPoint = true;
                    }

                    // 최대 변위값 추적 (CW 전진)
                    double currentDiffFwd2 = Math.Abs(MeasureData2.ValueLvdt - DiffStartTmp2_2);
                    if (currentDiffFwd2 > MaxDiffFwd2)
                    {
                        MaxDiffFwd2 = currentDiffFwd2;
                    }

                    WriteDiffLog2(35, "CW_MEASURE"); // CW 측정 로그
                    WriteDebugLog2(35, "CW_MEASURE", x, yGraph);

                    // CW 완료: 토크 > DiffLimitFwd (단, DiffLimitFwd<=0이면 SpecDiff 변위 도달 시 완료)
                    bool cwComplete2 = (MeasureData2.DiffLimitFwd > 0 && Math.Abs(MeasureData2.ValueReclTq) > MeasureData2.DiffLimitFwd)
                        || (MeasureData2.DiffLimitFwd <= 0 && currentDiffFwd2 >= MeasureData2.SpecDiff);
                    if (cwComplete2 && tmrWatch2.Elapsed.TotalSeconds > 1)
                    {
                        WriteDebugLog2(35, "CW_END", diff2LastX, diff2LastY);
                        WriteDiffLog2(35, "CW_END"); // CW 종료 로그
                        diff2CwEndX = diff2LastX; // CW 종료 X 좌표 저장 (복귀 시작점)
                        diff2CwEndLvdt = MeasureData2.ValueLvdt; // CW 종료 LVDT 저장
                        PLCData2.SetPlcBit(9, 1, false); //1축 CW OFF
                        WriteDiffLog2(35, "PLC_CW_OFF");
                        // PLCData2.SetPlcBit(9, 7, true); //1축 수동 정지 지령 - CCW 복귀 위해 주석 처리

                        if (diff2HasFirstPoint && diff2RedStartCaptured)
                        {
                            // CCW 끝점(검은 선 끝) → CW 시작점(빨간 선 시작) - 직선 연결 제거
                            // ClassZedGraph.DrawDirectLine(
                            //     PlotDiff2,
                            //     diff2BlackEndX, diff2BlackEndY,
                            //     diff2RedStartX, diff2RedStartY,
                            //     0
                            // );

                            // CW 끝점(빨간 선 끝) → CCW 시작점(검은 선 시작)
                            // 직선 연결 대신 CCW 복귀 측정으로 곡선 완성 (case 37.5~37.7)
                            // ClassZedGraph.DrawDirectLine(
                            //     PlotDiff2,
                            //     diff2LastX, diff2LastY,
                            //     diff2FirstX, diff2FirstY,
                            //     1
                            // );
                        }

                        // 유격 로그는 CCW 복귀 완료 후 닫음 (case 37.7)
                        // CloseDiffLog2();

                        tmrWatch2.Restart();
                        wStep2++;
                    }
                    }
                    break;

                case 36:
                    if (tmrWatch2.ElapsedMilliseconds > 1000)
                    {
                        DiffFwdTmp2 = MeasureData2.ValueLvdt;
                        tmrWatch2.Stop();
                        wStep2++;
                    }
                    break;

                case 37:

                    // lbBwdDiff2.Text = Math.Abs((MeasureData2.ValueLvdt) - DiffStartTmp2_2).ToString("F2"); // 원본 - 잘못된 매칭
                    // lbFwdDiff2.Text = Math.Abs((MeasureData2.ValueLvdt) - DiffStartTmp2_2).ToString("F2"); // 현재값 표시 (원복귀로 작게 나올 수 있음)
                    lbFwdDiff2.Text = MaxDiffFwd2.ToString("F2"); // CW(전진) 최대 변위 표시
                    lbTotalDiff2.Text = (Double.Parse(lbBwdDiff2.Text) + Double.Parse(lbFwdDiff2.Text)).ToString("F2");

                    double tmpf, tmpb, tmps, fval, bval, sval;

                    tmpf = Math.Abs(Double.Parse(lbFwdDiff2.Text));
                    tmpb = Math.Abs(Double.Parse(lbBwdDiff2.Text));
                    tmps = Math.Abs(Double.Parse(lbTotalDiff2.Text));

                    fval = Math.Floor((tmpf / 300) * (180 / 3.14) * 100) / 100.0;
                    bval = Math.Floor((tmpb / 300) * (180 / 3.14) * 100) / 100.0;
                    sval = Math.Floor((tmps / 300) * (180 / 3.14) * 100) / 100.0;

                    lbFwdDiffMeasure2.Text = fval.ToString("F2");
                    lbBwdDiffMeasure2.Text = bval.ToString("F2");
                    lbTotalDiffMeasure2.Text = (fval + bval).ToString("F2");

                    WriteMeasureLabelLog2("lbFwdDiff2", $"MaxDiffFwd2={MaxDiffFwd2:F4}", "CW 최대변위 mm", MaxDiffFwd2.ToString("F2"));
                    WriteMeasureLabelLog2("lbBwdDiff2", $"MaxDiffBwd2={MaxDiffBwd2:F4}", "CCW 최대변위 mm", lbBwdDiff2.Text);
                    WriteMeasureLabelLog2("lbFwdDiffMeasure2", $"tmpf={tmpf:F4}, 300, 180/π", "fval=Floor((tmpf/300)*(180/π)*100)/100 도(°)", fval.ToString("F2"));
                    WriteMeasureLabelLog2("lbBwdDiffMeasure2", $"tmpb={tmpb:F4}, 300, 180/π", "bval=Floor((tmpb/300)*(180/π)*100)/100 도(°)", bval.ToString("F2"));

                    JudgeAndSetLabelF2(0, MeasureData2.SpecDiff, fval + bval, lbTotalDiffMeasure2);
                    // 속도 복원은 CCW 복귀 완료 후 case 38에서 수행
                    // PLCData2.Servo1JogSpd = tmpBeforeSpeed2;
                    // PLCData2.FlagRecvAll = true;
                    // PLCData2.ServoSet();
                    WriteDiffLog2(37, $"SPEED_KEEP_DIFF: DiffSpeed={PLCData2.DiffSpeed}, CurrentSpd={PLCData2.Servo1JogSpd}");
                    WriteDebugLog2(37, $"RESULT:FwdDiff={MaxDiffFwd2:F4},BwdDiff={MaxDiffBwd2:F4},fval={fval:F4},bval={bval:F4}");
                    wStep2 = 37.1;
                    break;

                case 37.1: // 알람 확인 및 리셋 (무조건 리셋 후 진행) — 3회 재시도
                    if (_alarmRetryCount2 >= 3)
                    {
                        Logger.LogOnce("[2] 서보 알람 3회 초과", "[2] 서보 알람 3회 초과 — step 37.1(CW 완료 후 알람 리셋)에서 정지. 설비 점검 필요.");
                        CloseDiffLog2();
                        CloseDebugLog2();
                        wStep2 = 99;
                    }
                    else
                    {
                        _alarmAtStep2 = 37.1;
                        _alarmRetryCount2++;
                        WriteDiffLog2(37.1, "ALARM_CHECK");
                        PLCData2.SetPlcBit(9, 7, false); //1축 수동 정지 지령 해제
                        PLCData2.SetPlcBit(9, 3, true); //1축 알람 리셋
                        PLCData2.SetPlcBit(11, 3, true); //2축 알람 리셋
                        WriteDiffLog2(37.1, "ALARM_RESET_ON");
                        tmrWatch2.Restart();
                        wStep2 = 37.2;
                    }
                    break;

                case 37.2: // 알람 리셋 대기 (1초)
                    if (tmrWatch2.ElapsedMilliseconds > 1000)
                    {
                        tmrWatch2.Stop();
                        PLCData2.SetPlcBit(9, 3, false); //1축 알람 리셋 OFF
                        PLCData2.SetPlcBit(11, 3, false); //2축 알람 리셋 OFF
                        WriteDiffLog2(37.2, "ALARM_RESET_OFF");
                        wStep2 = 37.3;
                    }
                    break;

                case 37.3: // 알람 해제 확인
                    if (PLCData2.PlcValueBit[8, 1] == false && PLCData2.PlcValueBit[10, 1] == false)
                    {
                        _alarmRetryCount2 = 0; // 복구 성공 시 재시도 카운트 리셋
                        WriteDiffLog2(37.3, "ALARM_CLEARED");
                        tmrWatch2.Restart();
                        wStep2 = 37.4; // 딜레이 후 CCW 복귀
                    }
                    else
                    {
                        WriteDiffLog2(37.3, "ALARM_STILL_ON");
                        if (_alarmRetryCount2 >= 3)
                        {
                            Logger.LogOnce("[2] 서보 알람 3회 초과", "[2] 서보 알람 3회 초과 — step 37.1(CW 완료 후 알람 리셋)에서 정지. 설비 점검 필요.");
                            CloseDiffLog2();
                            CloseDebugLog2();
                            wStep2 = 99;
                        }
                        else
                            wStep2 = 37.1; // 알람 아직 있으면 다시 리셋
                    }
                    break;

                case 37.4: // CCW 복귀 전 딜레이 (1초 대기)
                    WriteDiffLog2(37.4, "CCW_RETURN_DELAY");
                    if (tmrWatch2.ElapsedMilliseconds > 1000)
                    {
                        WriteDiffLog2(37.4, "CCW_RETURN_DELAY_END");
                        wStep2 = 37.5;
                    }
                    break;

                case 37.5: // CCW 복귀 측정 시작 (토크 0까지)
                    WriteDiffLog2(37.5, "CCW_RETURN_START");
                    WriteDebugLog2(37.5, "CCW_RETURN_START");
                    PLCData2.SetPlcBit(9, 6, true);  // 1축 수동 ON
                    WriteDiffLog2(37.5, "PLC_MANUAL_ON");
                    PLCData2.SetPlcBit(9, 7, false); // 1축 수동 정지 지령 해제
                    WriteDiffLog2(37.5, "PLC_STOP_OFF");
                    PLCData2.SetPlcBit(9, 1, false); // 1축 CW OFF
                    WriteDiffLog2(37.5, "PLC_CW_OFF");
                    PLCData2.SetPlcBit(9, 2, true);  // 1축 CCW ON
                    WriteDiffLog2(37.5, "PLC_CCW_ON");
                    // diff2CwEndX, diff2CwEndLvdt는 case 35 CW_END에서 이미 저장됨
                    // 복귀선 첫 점을 CW 마지막 좌표에 찍어서 연결
                    ClassZedGraph.DrawGraphLine(PlotDiff2, diff2LastX, diff2LastY, 2);
                    tmrWatch2.Restart();
                    wStep2 = 37.6;
                    break;

                case 37.6: // CCW 복귀 - 토크 0까지 이동
                    {
                        double xReturn = diff2CwEndX + (MeasureData2.ValueLvdt - diff2CwEndLvdt);
                        double yReturn = tmpNum2 * -1 * MeasureData2.ValueReclTq;

                        // 토크가 음수(CW방향)일 때만 복귀 곡선 그리기
                        if (yReturn <= 0)
                        {
                            ClassZedGraph.DrawGraphLine(PlotDiff2, xReturn, yReturn, 2); // 파랑 선 (복귀)
                            diff2LastX = xReturn;
                            diff2LastY = yReturn;
                        }
                        WriteDiffLog2(37.6, "CCW_RETURN_MEASURE");
                        WriteDebugLog2(37.6, "CCW_RETURN_MEASURE", xReturn, yReturn);

                        // 토크 60 Nm 초과 시 강제 정지 (서보 과부하 방지)
                        if (Math.Abs(MeasureData2.ValueReclTq) > 60)
                        {
                            _alarmRetryCount2 = 0;
                            Logger.LogOnce("[2] CCW 복귀 중 토크 60 Nm 초과 - 강제 정지");
                            WriteDiffLog2(37.6, "CCW_RETURN_TORQUE_OVER_60");
                            WriteDebugLog2(37.6, "CCW_RETURN_TORQUE_OVER_60", xReturn, yReturn);
                            PLCData2.SetPlcBit(9, 2, false); // CCW OFF
                            PLCData2.SetPlcBit(9, 7, true);  // 수동 정지
                            CloseDiffLog2();
                            CloseDebugLog2();
                            wStep2 = 38;
                        }
                        // 토크가 0 근처에 도달하면 완료
                        else if (Math.Abs(MeasureData2.ValueReclTq) < 0.5)
                        {
                            _alarmRetryCount2 = 0; // 정상 완료 시 재시도 카운트 리셋
                            ClassZedGraph.DrawGraphLine(PlotDiff2, 0, 0, 2); // 그래프 원점으로 루프 닫기
                            WriteDiffLog2(37.6, "CCW_RETURN_END");
                            PLCData2.SetPlcBit(9, 2, false); // CCW OFF
                            WriteDiffLog2(37.6, "PLC_CCW_OFF");
                            PLCData2.SetPlcBit(9, 7, true);  // 수동 정지
                            WriteDiffLog2(37.6, "PLC_STOP_ON");
                            CloseDiffLog2();
                            CloseDebugLog2();
                            wStep2 = 38;
                        }
                        // 타임아웃: 15초 내 토크 0 미도달 시 강제 완료
                        else if (tmrWatch2.Elapsed.TotalSeconds > 15)
                        {
                            _alarmRetryCount2 = 0;
                            WriteDiffLog2(37.6, "CCW_RETURN_TIMEOUT");
                            WriteDebugLog2(37.6, "CCW_RETURN_TIMEOUT", xReturn, yReturn);
                            PLCData2.SetPlcBit(9, 2, false); // CCW OFF
                            PLCData2.SetPlcBit(9, 7, true);  // 수동 정지
                            CloseDiffLog2();
                            CloseDebugLog2();
                            wStep2 = 38;
                        }
                        // 서보 알람 시 자동 에러리셋 후 재시도 (최대 3회)
                        else if (PLCData2.PlcValueBit[8, 1] == true || PLCData2.PlcValueBit[10, 1] == true)
                        {
                            if (_alarmRetryCount2 >= 3)
                            {
                                Logger.LogOnce("[2] 서보 알람 3회 초과", "[2] 서보 알람 3회 초과 — step 37.6(CCW 복귀)에서 정지. 설비 점검 필요.");
                                CloseDiffLog2();
                                CloseDebugLog2();
                                wStep2 = 99;
                            }
                            else
                            {
                                _alarmAtStep2 = 37.6;
                                _alarmRetryCount2++;
                                Logger.LogOnce("[2] CCW 복귀 중 서보 알람 - 에러리셋");
                                WriteDiffLog2(37.6, "SERVO_ALARM_RESET");
                                PLCData2.SetPlcBit(9, 2, false); // CCW OFF
                                PLCData2.SetPlcBit(9, 7, false); // 수동 정지 해제
                                PLCData2.SetPlcBit(9, 3, true);  // 1축 알람 리셋
                                PLCData2.SetPlcBit(11, 3, true); // 2축 알람 리셋
                                tmrWatch2.Restart();
                                wStep2 = 37.61;
                            }
                        }
                    }
                    break;

                case 37.61: // 서보 알람 에러리셋 대기 — 알람 해제 시 진행, 최소 1초·최대 2초
                    bool alarmCleared2 = PLCData2.PlcValueBit[8, 1] == false && PLCData2.PlcValueBit[10, 1] == false;
                    bool minElapsed2 = tmrWatch2.ElapsedMilliseconds >= 1000; // 리셋 펄스 최소 1초
                    bool timeout2 = tmrWatch2.ElapsedMilliseconds > 2000;
                    if ((minElapsed2 && alarmCleared2) || timeout2)
                    {
                        if (timeout2 && !alarmCleared2)
                            Logger.LogOnce("[2] CCW 복귀 서보 알람 — 2초 내 미해제, 진행");
                        PLCData2.SetPlcBit(9, 3, false);  // 1축 알람 리셋 OFF
                        PLCData2.SetPlcBit(11, 3, false); // 2축 알람 리셋 OFF
                        PLCData2.SetPlcBit(9, 9, true);   // 1축 서보 온
                        PLCData2.SetPlcBit(11, 9, true);  // 2축 서보 온
                        CloseDiffLog2();
                        CloseDebugLog2();
                        wStep2 = 37.5; // CCW 복귀 재시도 (3회 초과 시 다음 37.6에서 99로 정지)
                    }
                    break;

                case 38:
                    // 속도 복원 (원래 속도로)
                    WriteDiffLog2(38, $"SPEED_RESTORE: BeforeSpeed={tmpBeforeSpeed2}, CurrentSpd={PLCData2.Servo1JogSpd}");
                    PLCData2.Servo1JogSpd = tmpBeforeSpeed2;
                    PLCData2.FlagRecvAll = true;
                    PLCData2.ServoSet();

                    PLCData2.SetPlcBit(9, 7, false); //1축 수동 정지 지령
                    PLCData2.SetPlcBit(9, 5, true); //1축 자동 ON
                    PLCData2.SetPlcBit(11, 5, true); //2축 자동 ON
                    PLCData2.SetPlcBit(9, 6, false); //1축 수동 OFF
                    PLCData2.SetPlcBit(11, 6, false); //2축 수동 OFF
                    _csv2.Save($"{tmpsave2}_Diff");
                    wStep2++;
                    break;

                case 39:
                    PLCData2.SetPlcBit(4, 12, true); //LVDT 후진 지령 D4004.12
                    wStep2++;
                    break;

                case 40:
                    if (PLCData2.PlcValueBit[0, 10] == true || PLCData2.PlcValueBit[0, 13] == true) // LVDT 후진, 가이드 후진 2
                    {
                        PLCData2.SetPlcBit(4, 12, false); //LVDT 후진 지령 D4004.12
                        PLCData2.FlagRecvAll = false;
                        wStep2++;
                    }
                    break;

                case 41:
                    if (!_lever41Delay2)
                    {
                        PLCData2.SetPlcBit(13, 1, true); //2축 2번 포지션,레버 해제
                        tmrWatch2.Restart();
                        _lever41Delay2 = true;
                    }
                    else if (tmrWatch2.ElapsedMilliseconds >= 2000)
                    {
                        _lever41Delay2 = false;
                        wStep2 = 42;
                    }
                    break;

                case 42:
                    bool complete15_2 = PLCData2.PlcValueBit[15, 1];
                    bool command13_2 = PLCData2.PlcValueBit[13, 1];
                    bool alarm8_2 = PLCData2.PlcValueBit[8, 1];
                    bool alarm10_2 = PLCData2.PlcValueBit[10, 1];
                    if (complete15_2 && command13_2) //완료 AND 명령 동시 ON
                    {
                        _alarmRetryCount2 = 0; // 레버 완료 시 재시도 카운트 리셋
                        Logger.LogOnce("[2] 레버 해제 완료");
                        PLCData2.SetPlcBit(13, 1, false); //레버 해제 완료
                        PLCData2.SetPlcBit(9, 3, true);   // 1축 에러 리셋
                        PLCData2.SetPlcBit(11, 3, true);  // 2축 에러 리셋
                        tmrWatch2.Restart();
                        wStep2 = 42.1;
                    }
                    else if (alarm8_2 || alarm10_2)
                    {
                        if (_alarmRetryCount2 >= 3)
                        {
                            Logger.LogOnce("[2] 서보 알람 3회 초과", "[2] 서보 알람 3회 초과 — step 42(레버 포지션 완료 대기)에서 정지. 설비 점검 필요.");
                            wStep2 = 99;
                        }
                        else
                        {
                            _alarmAtStep2 = 42;
                            _alarmRetryCount2++;
                            Logger.LogOnce("[2] step42 서보 알람 - 에러리셋 후 재시도");
                            PLCData2.SetPlcBit(13, 1, false);
                            PLCData2.SetPlcBit(9, 3, true);
                            PLCData2.SetPlcBit(11, 3, true);
                            tmrWatch2.Restart();
                            wStep2 = 42.1;
                        }
                    }
                    break;

                case 42.1: // 에러 리셋 후 서보 온까지 대기 (최소 1초·최대 2초)
                    bool alarmCleared42_2 = PLCData2.PlcValueBit[8, 1] == false && PLCData2.PlcValueBit[10, 1] == false;
                    bool minElapsed42_2 = tmrWatch2.ElapsedMilliseconds >= 1000;
                    bool timeout42_2 = tmrWatch2.ElapsedMilliseconds > 2000;
                    if ((minElapsed42_2 && alarmCleared42_2) || timeout42_2)
                    {
                        if (timeout42_2 && !alarmCleared42_2)
                            Logger.LogOnce("[2] step 42 에러리셋 — 2초 내 미해제, 진행");
                        PLCData2.SetPlcBit(9, 3, false);  // 1축 알람 리셋 OFF
                        PLCData2.SetPlcBit(11, 3, false); // 2축 알람 리셋 OFF
                        PLCData2.SetPlcBit(9, 9, true);   // 1축 서보 온
                        PLCData2.SetPlcBit(11, 9, true);  // 2축 서보 온
                        if (_alarmAtStep2 == 42)
                        {
                            _alarmAtStep2 = 0;
                            wStep2 = 41; // 레버 포지션 재시도
                        }
                        else
                            wStep2 = 43;
                    }
                    break;

                case 43:
                    Logger.LogOnce("[2] 1축 1번 포지션 이동 시작");
                    PLCData2.SetPlcBit(12, 0, true); //1축 1번 포지션
                    wStep2++;
                    break;

                case 44:
                    if (PLCData2.PlcValueBit[14, 0] == true && PLCData2.PlcValueBit[12, 0] == true) //완료 AND 명령 동시 ON
                    {
                        PLCData2.SetPlcBit(12, 0, false);
                        wStep2++;
                    }
                    break;

                case 45:
                    PLCData2.SetPlcBit(13, 0, true); //2축 1번 포지션,레버 원위치
                    wStep2++;
                    break;

                case 46:
                    if (PLCData2.PlcValueBit[15, 0] == true && PLCData2.PlcValueBit[13, 0] == true) //완료 AND 명령 동시 ON
                    {
                        PLCData2.SetPlcBit(13, 0, false); //레버 해제 완료
                        wStep2++;
                    }
                    break;

                case 47:

                    PLCData2.SetPlcBit(4, 8, true); //클램프 상승 지령 D4004.8
                    PLCData2.SetPlcBit(4, 10, true); //클램프 후진
                    tmrRstWatch2.Restart();
                    wStep2++;
                    break;

                case 48:
                    if (PLCData2.PlcValueBit[0, 6] == true) //클램프 상승
                    {
                        PLCData2.SetPlcBit(4, 8, false); //클램프 상승 지령 D4004.8
                    }
                    if (PLCData2.PlcValueBit[0, 9] == true) //클램프 후진 D4000.9
                    {
                        PLCData2.SetPlcBit(4, 10, false); //클램프 후진
                    }
                    if (PLCData2.PlcValueBit[0, 6] == true && PLCData2.PlcValueBit[0, 9] == true)
                    {
                        wStep2++;
                    }
                    break;

                case 49:
                    Logger.LogOnce("[2] 데이터 저장");
                    InsertData(lbBarcode2.Text, lbLPartNo2.Text,
                               lbReclFwdMeasure2.Text, CheckLabelStatus(lbReclFwdMeasure2),
                               lbReclBwdMeasure2.Text, CheckLabelStatus(lbReclBwdMeasure2),
                               lbLeverMeasure2.Text, CheckLabelStatus(lbLeverMeasure2),
                               lbFwdDiffMeasure2.Text, lbBwdDiffMeasure2.Text,
                               lbTotalDiffMeasure2.Text, CheckLabelStatus(lbTotalDiffMeasure2));
                    wStep2++;
                    break;

                case 50:

                    if (lbReclFwdMeasure2.BackColor == System.Drawing.Color.Blue &&
                        lbReclBwdMeasure2.BackColor == System.Drawing.Color.Blue &&
                        lbLeverMeasure2.BackColor == System.Drawing.Color.Blue &&
                        lbTotalDiffMeasure2.BackColor == System.Drawing.Color.Blue)
                    {
                        PlaySound("DINGDONG.wav");
                        BarcodePrint2();
                        Logger.LogOnce("[2] 바코드 출력");
                        CloseMeasureLog2();
                        GlobalValues.OkCount++;
                        GlobalValues.TotalCount++;
                        lbOkCount.Text = GlobalValues.OkCount.ToString();
                        lbNGCount.Text = (GlobalValues.TotalCount - GlobalValues.OkCount).ToString();
                        lbTotalCount.Text = GlobalValues.TotalCount.ToString();
                        GlobalValues.SaveCounts();
                    }
                    else
                    {
                        CloseMeasureLog2();
                        BarcodePrintNg2();
                        PlaySound("NG.wav");
                        GlobalValues.TotalCount++;
                        lbOkCount.Text = GlobalValues.OkCount.ToString();
                        lbNGCount.Text = (GlobalValues.TotalCount - GlobalValues.OkCount).ToString();
                        lbTotalCount.Text = GlobalValues.TotalCount.ToString();
                        GlobalValues.SaveCounts();
                    }
                    wStep2 = 51;
                    break;

                case 51:
                    if (tmrWatch2.ElapsedMilliseconds > 1000)
                    {
                        wStep2 = 0;
                        _lever41Delay2 = false;
                        _alarmRetryCount2 = 0;
                        _alarmAtStep2 = 0;
                    }
                    break;

                case 99: // 서보 알람 3회 초과 정지 — 리셋 전까지 대기
                    break;

            }

        }


