        #region "CELL"

        private StringBuilder bufferLeverTq1 = new StringBuilder();
        private StringBuilder bufferLeverTq2 = new StringBuilder();
        private StringBuilder bufferReclTq1 = new StringBuilder();
        private StringBuilder bufferReclTq2 = new StringBuilder();
        private void SerialCell_DataReceived(object sender, SerialDataReceivedEventArgs e)
        {
            var sp = sender as SerialPort;
            if (sp == null) return;
            try
            {
                string response = sp.ReadExisting();
                if (string.IsNullOrWhiteSpace(response)) return;

                // 각 포트별 버퍼를 따로 유지                
                if (sp == SerialLeverTq1) bufferLeverTq1.Append(response);
                else if (sp == SerialLeverTq2) bufferLeverTq2.Append(response);
                else if (sp == SerialReclTq1) { bufferReclTq1.Append(response); _lastReclTq1Rx = DateTime.Now; }
                else if (sp == SerialReclTq2) { bufferReclTq2.Append(response); _lastReclTq2Rx = DateTime.Now; }

                // 포트별로 파싱
                if (sp == SerialLeverTq1) ParseBuffer(sp, bufferLeverTq1, 0);
                else if (sp == SerialLeverTq2) ParseBuffer(sp, bufferLeverTq2, 1);
                else if (sp == SerialReclTq1) ParseBuffer(sp, bufferReclTq1, 2);
                else if (sp == SerialReclTq2) ParseBuffer(sp, bufferReclTq2, 3);
            }
            catch (Exception ex)
            {
                this.Invoke((MethodInvoker)(() =>
                    Logger.LogOnce("시리얼 수신 오류", $"[{sp.PortName}] 수신 오류: {ex.Message}")));
            }
        }
        private void ParseBuffer(SerialPort sp, StringBuilder buffer, int portIndex)
        {
            string raw = buffer.ToString();
            int startIdx = raw.IndexOf((char)0x02); // STX
            int endIdx = raw.IndexOf((char)0x03);   // ETX

            if (startIdx >= 0 && endIdx > startIdx)
            {
                string packet = raw.Substring(startIdx + 1, endIdx - startIdx - 1); // STX~ETX 제외
                string valueStr = packet.Substring(1).Trim(); // 첫 문자 제외하고 숫자                
                string cleaned = valueStr.Replace(" ", ""); // → "+0.0
                if (double.TryParse(cleaned, out double val))
                {
                    this.Invoke((MethodInvoker)(() =>
                    {
                        switch (portIndex)
                        {
                            case 0:
                                MeasureData1.ValueLeverTq = Math.Abs(val) * MeasureData1.ValueLeverTqTol;
                                lbLeverTq1.Text = $"{MeasureData1.ValueLeverTq:F1}";
                                break;
                            case 1:
                                MeasureData2.ValueLeverTq = Math.Abs(val) * MeasureData2.ValueLeverTqTol;
                                lbLeverTq2.Text = $"{MeasureData2.ValueLeverTq:F1}";
                                break;
                            case 2:
                                MeasureData1.ValueReclTq = (val) * MeasureData1.ValueReclTqTol;
                                lbReclTq1.Text = $"{MeasureData1.ValueReclTq:F1}";
                                _lastReclTq1Parse = DateTime.Now;
                                _reclTq1WarningSent = false;
                                _reclTq1RetryCount = 0;
                                break;
                            case 3:
                                MeasureData2.ValueReclTq = (val) * MeasureData2.ValueReclTqTol;
                                lbReclTq2.Text = $"{MeasureData2.ValueReclTq:F1}";
                                _lastReclTq2Parse = DateTime.Now;
                                _reclTq2WarningSent = false;
                                _reclTq2RetryCount = 0;
                                break;
                        }
                    }));
                }
                else
                {
                    // ReclTq: TryParse 실패 — 진단 로그 및 재시도
                    if (portIndex == 2)
                    {
                        Logger.LogOnce("[토크진단]ReclTq1 파싱실패", $"[토크진단] ReclTq1 파싱실패: '{valueStr}'");
                        if (_reclTq1RetryCount < 3)
                        {
                            _reclTq1RetryCount++;
                            try { if (SerialReclTq1.IsOpen) SerialReclTq1.Write("1R"); } catch { }
                            if (_reclTq1RetryCount >= 3)
                                Logger.Log("[토크진단] ReclTq1 3회 재시도 후 실패 — 연결 불가로 간주");
                        }
                    }
                    else if (portIndex == 3)
                    {
                        Logger.LogOnce("[토크진단]ReclTq2 파싱실패", $"[토크진단] ReclTq2 파싱실패: '{valueStr}'");
                        if (_reclTq2RetryCount < 3)
                        {
                            _reclTq2RetryCount++;
                            try { if (SerialReclTq2.IsOpen) SerialReclTq2.Write("1R"); } catch { }
                            if (_reclTq2RetryCount >= 3)
                                Logger.Log("[토크진단] ReclTq2 3회 재시도 후 실패 — 연결 불가로 간주");
                        }
                    }
                }
                //남은 데이터 보존
                raw = raw.Substring(endIdx + 1);
                buffer.Clear();
                buffer.Append(raw);
            }
            else
            {
                // STX/ETX 없음 — ReclTq 진단 및 재시도
                if (portIndex == 2)
                {
                    Logger.LogOnce("[토크진단]ReclTq1 STX/ETX없음", $"[토크진단] ReclTq1 STX/ETX 없음, raw길이={raw.Length}");
                    if (_reclTq1RetryCount < 3)
                    {
                        _reclTq1RetryCount++;
                        try { if (SerialReclTq1.IsOpen) SerialReclTq1.Write("1R"); } catch { }
                        if (_reclTq1RetryCount >= 3)
                            Logger.Log("[토크진단] ReclTq1 3회 재시도 후 실패 — 연결 불가로 간주");
                    }
                }
                else if (portIndex == 3)
                {
                    Logger.LogOnce("[토크진단]ReclTq2 STX/ETX없음", $"[토크진단] ReclTq2 STX/ETX 없음, raw길이={raw.Length}");
                    if (_reclTq2RetryCount < 3)
                    {
                        _reclTq2RetryCount++;
                        try { if (SerialReclTq2.IsOpen) SerialReclTq2.Write("1R"); } catch { }
                        if (_reclTq2RetryCount >= 3)
                            Logger.Log("[토크진단] ReclTq2 3회 재시도 후 실패 — 연결 불가로 간주");
                    }
                }
            }
        }
        private void RequestTorqueAll()
        {
            try
            {
                if (SerialLeverTq1.IsOpen) SerialLeverTq1.Write("1R");
                if (SerialLeverTq2.IsOpen) SerialLeverTq2.Write("1R");
                if (SerialReclTq1.IsOpen) SerialReclTq1.Write("1R");
                if (SerialReclTq2.IsOpen) SerialReclTq2.Write("1R");
            }
            catch (Exception ex)
            {
                Logger.LogOnce("[요청오류]", $"[요청오류] {ex.Message}");
            }
        }
        private void ResetLeverTq1() => ResetTorque(SerialLeverTq1, "LeverTq1");
        private void ResetLeverTq2() => ResetTorque(SerialLeverTq2, "LeverTq2");
        private void ResetReclTq1() => ResetTorque(SerialReclTq1, "ReclTq1");
        private void ResetReclTq2() => ResetTorque(SerialReclTq2, "ReclTq2");
        private void ResetTorque(SerialPort sp, string name)
        {
            try
            {
                if (sp.IsOpen)
                {
                    sp.Write("1Z");
                    Logger.LogOnce("리셋 명령 전송됨", $"[{name}] 리셋 명령 전송됨");
                }
                else
                {
                    Logger.LogOnce("포트가 열려있지 않음", $"[{name}] 포트가 열려있지 않음");
                }
            }
            catch (Exception ex)
            {
