                            PLCData2.SetPlcBit(9, 2, false); // CCW OFF
                            WriteDiffLog2(37.6, "PLC_CCW_OFF");
                            PLCData2.SetPlcBit(9, 7, true);  // 수동 정지
                            WriteDiffLog2(37.6, "PLC_STOP_ON");
                            CloseDiffLog2();
                            CloseDebugLog2();
                            wStep2 = 38;
                        }
                        // 타임아웃: 15초 내 토크 0 미도달 시 강제 완료
                        else if (tmrWatch2.Elapsed.TotalSeconds > 15)
                        {
                            _alarmRetryCount2 = 0;
                            WriteDiffLog2(37.6, "CCW_RETURN_TIMEOUT");
                            WriteDebugLog2(37.6, "CCW_RETURN_TIMEOUT", xReturn, yReturn);
                            PLCData2.SetPlcBit(9, 2, false); // CCW OFF
                            PLCData2.SetPlcBit(9, 7, true);  // 수동 정지
                            CloseDiffLog2();
                            CloseDebugLog2();
                            wStep2 = 38;
                        }
                        // 서보 알람 시 자동 에러리셋 후 재시도 (최대 3회)
                        else if (PLCData2.PlcValueBit[8, 1] == true || PLCData2.PlcValueBit[10, 1] == true)
                        {
                            if (_alarmRetryCount2 >= 3)
                            {
                                Logger.LogOnce("[2] 서보 알람 3회 초과", "[2] 서보 알람 3회 초과 — step 37.6(CCW 복귀)에서 정지. 설비 점검 필요.");
                                CloseDiffLog2();
                                CloseDebugLog2();
                                wStep2 = 99;
                            }
                            else
                            {
                                _alarmAtStep2 = 37.6;
                                _alarmRetryCount2++;
                                Logger.LogOnce("[2] CCW 복귀 중 서보 알람 - 에러리셋");
                                WriteDiffLog2(37.6, "SERVO_ALARM_RESET");
                                PLCData2.SetPlcBit(9, 2, false); // CCW OFF
                                PLCData2.SetPlcBit(9, 7, false); // 수동 정지 해제
                                PLCData2.SetPlcBit(9, 3, true);  // 1축 알람 리셋
                                PLCData2.SetPlcBit(11, 3, true); // 2축 알람 리셋
                                tmrWatch2.Restart();
                                wStep2 = 37.61;
                            }
                        }
                    }
                    break;

                case 37.61: // 서보 알람 에러리셋 대기 — 알람 해제 시 진행, 최소 1초·최대 2초
                    bool alarmCleared2 = PLCData2.PlcValueBit[8, 1] == false && PLCData2.PlcValueBit[10, 1] == false;
                    bool minElapsed2 = tmrWatch2.ElapsedMilliseconds >= 1000; // 리셋 펄스 최소 1초
                    bool timeout2 = tmrWatch2.ElapsedMilliseconds > 2000;
                    if ((minElapsed2 && alarmCleared2) || timeout2)
                    {
                        if (timeout2 && !alarmCleared2)
                            Logger.LogOnce("[2] CCW 복귀 서보 알람 — 2초 내 미해제, 진행");
                        PLCData2.SetPlcBit(9, 3, false);  // 1축 알람 리셋 OFF
                        PLCData2.SetPlcBit(11, 3, false); // 2축 알람 리셋 OFF
                        PLCData2.SetPlcBit(9, 9, true);   // 1축 서보 온
                        PLCData2.SetPlcBit(11, 9, true);  // 2축 서보 온
                        CloseDiffLog2();
                        CloseDebugLog2();
                        wStep2 = 37.5; // CCW 복귀 재시도 (3회 초과 시 다음 37.6에서 99로 정지)
                    }
                    break;

                case 38:
                    // 속도 복원 (원래 속도로)
                    WriteDiffLog2(38, $"SPEED_RESTORE: BeforeSpeed={tmpBeforeSpeed2}, CurrentSpd={PLCData2.Servo1JogSpd}");
                    PLCData2.Servo1JogSpd = tmpBeforeSpeed2;
                    PLCData2.FlagRecvAll = true;
                    PLCData2.ServoSet();

                    PLCData2.SetPlcBit(9, 7, false); //1축 수동 정지 지령
                    PLCData2.SetPlcBit(9, 5, true); //1축 자동 ON
                    PLCData2.SetPlcBit(11, 5, true); //2축 자동 ON
                    PLCData2.SetPlcBit(9, 6, false); //1축 수동 OFF
                    PLCData2.SetPlcBit(11, 6, false); //2축 수동 OFF
                    _csv2.Save($"{tmpsave2}_Diff");
                    wStep2++;
                    break;

                case 39:
                    PLCData2.SetPlcBit(4, 12, true); //LVDT 후진 지령 D4004.12
                    wStep2++;
                    break;

                case 40:
                    if (PLCData2.PlcValueBit[0, 10] == true || PLCData2.PlcValueBit[0, 13] == true) // LVDT 후진, 가이드 후진 2
                    {
                        PLCData2.SetPlcBit(4, 12, false); //LVDT 후진 지령 D4004.12
                        PLCData2.FlagRecvAll = false;
                        wStep2++;
                    }
                    break;

                case 41:
                    if (!_lever41Delay2)
                    {
                        PLCData2.SetPlcBit(13, 1, true); //2축 2번 포지션,레버 해제
                        tmrWatch2.Restart();
                        _lever41Delay2 = true;
                    }
                    else if (tmrWatch2.ElapsedMilliseconds >= 2000)
                    {
                        _lever41Delay2 = false;
                        wStep2 = 42;
                    }
                    break;

                case 42:
                    bool complete15_2 = PLCData2.PlcValueBit[15, 1];
                    bool command13_2 = PLCData2.PlcValueBit[13, 1];
                    bool alarm8_2 = PLCData2.PlcValueBit[8, 1];
                    bool alarm10_2 = PLCData2.PlcValueBit[10, 1];
                    if (complete15_2 && command13_2) //완료 AND 명령 동시 ON
                    {
                        _alarmRetryCount2 = 0; // 레버 완료 시 재시도 카운트 리셋
                        Logger.LogOnce("[2] 레버 해제 완료");
                        PLCData2.SetPlcBit(13, 1, false); //레버 해제 완료
                        PLCData2.SetPlcBit(9, 3, true);   // 1축 에러 리셋
                        PLCData2.SetPlcBit(11, 3, true);  // 2축 에러 리셋
                        tmrWatch2.Restart();
                        wStep2 = 42.1;
                    }
                    else if (alarm8_2 || alarm10_2)
                    {
                        if (_alarmRetryCount2 >= 3)
                        {
                            Logger.LogOnce("[2] 서보 알람 3회 초과", "[2] 서보 알람 3회 초과 — step 42(레버 포지션 완료 대기)에서 정지. 설비 점검 필요.");
                            wStep2 = 99;
                        }
                        else
                        {
                            _alarmAtStep2 = 42;
                            _alarmRetryCount2++;
                            Logger.LogOnce("[2] step42 서보 알람 - 에러리셋 후 재시도");
                            PLCData2.SetPlcBit(13, 1, false);
                            PLCData2.SetPlcBit(9, 3, true);
                            PLCData2.SetPlcBit(11, 3, true);
                            tmrWatch2.Restart();
                            wStep2 = 42.1;
                        }
                    }
                    break;

                case 42.1: // 에러 리셋 후 서보 온까지 대기 (최소 1초·최대 2초)
                    bool alarmCleared42_2 = PLCData2.PlcValueBit[8, 1] == false && PLCData2.PlcValueBit[10, 1] == false;
                    bool minElapsed42_2 = tmrWatch2.ElapsedMilliseconds >= 1000;
                    bool timeout42_2 = tmrWatch2.ElapsedMilliseconds > 2000;
                    if ((minElapsed42_2 && alarmCleared42_2) || timeout42_2)
                    {
                        if (timeout42_2 && !alarmCleared42_2)
                            Logger.LogOnce("[2] step 42 에러리셋 — 2초 내 미해제, 진행");
                        PLCData2.SetPlcBit(9, 3, false);  // 1축 알람 리셋 OFF
                        PLCData2.SetPlcBit(11, 3, false); // 2축 알람 리셋 OFF
                        PLCData2.SetPlcBit(9, 9, true);   // 1축 서보 온
                        PLCData2.SetPlcBit(11, 9, true);  // 2축 서보 온
                        if (_alarmAtStep2 == 42)
                        {
                            _alarmAtStep2 = 0;
                            wStep2 = 41; // 레버 포지션 재시도
                        }
                        else
                            wStep2 = 43;
                    }
                    break;

                case 43:
                    Logger.LogOnce("[2] 1축 1번 포지션 이동 시작");
                    PLCData2.SetPlcBit(12, 0, true); //1축 1번 포지션
                    wStep2++;
                    break;

                case 44:
                    if (PLCData2.PlcValueBit[14, 0] == true && PLCData2.PlcValueBit[12, 0] == true) //완료 AND 명령 동시 ON
                    {
                        PLCData2.SetPlcBit(12, 0, false);
                        wStep2++;
                    }
                    break;

                case 45:
                    PLCData2.SetPlcBit(13, 0, true); //2축 1번 포지션,레버 원위치
                    wStep2++;
                    break;

                case 46:
                    if (PLCData2.PlcValueBit[15, 0] == true && PLCData2.PlcValueBit[13, 0] == true) //완료 AND 명령 동시 ON
                    {
                        PLCData2.SetPlcBit(13, 0, false); //레버 해제 완료
                        wStep2++;
                    }
                    break;

                case 47:

                    PLCData2.SetPlcBit(4, 8, true); //클램프 상승 지령 D4004.8
                    PLCData2.SetPlcBit(4, 10, true); //클램프 후진
                    tmrRstWatch2.Restart();
                    wStep2++;
                    break;

                case 48:
                    if (PLCData2.PlcValueBit[0, 6] == true) //클램프 상승
                    {
                        PLCData2.SetPlcBit(4, 8, false); //클램프 상승 지령 D4004.8
                    }
                    if (PLCData2.PlcValueBit[0, 9] == true) //클램프 후진 D4000.9
                    {
                        PLCData2.SetPlcBit(4, 10, false); //클램프 후진
                    }
                    if (PLCData2.PlcValueBit[0, 6] == true && PLCData2.PlcValueBit[0, 9] == true)
                    {
                        wStep2++;
                    }
                    break;

                case 49:
                    Logger.LogOnce("[2] 데이터 저장");
                    InsertData(lbBarcode2.Text, lbLPartNo2.Text,
                               lbReclFwdMeasure2.Text, CheckLabelStatus(lbReclFwdMeasure2),
                               lbReclBwdMeasure2.Text, CheckLabelStatus(lbReclBwdMeasure2),
                               lbLeverMeasure2.Text, CheckLabelStatus(lbLeverMeasure2),
                               lbFwdDiffMeasure2.Text, lbBwdDiffMeasure2.Text,
                               lbTotalDiffMeasure2.Text, CheckLabelStatus(lbTotalDiffMeasure2));
                    wStep2++;
                    break;

                case 50:

                    if (lbReclFwdMeasure2.BackColor == System.Drawing.Color.Blue &&
                        lbReclBwdMeasure2.BackColor == System.Drawing.Color.Blue &&
                        lbLeverMeasure2.BackColor == System.Drawing.Color.Blue &&
                        lbTotalDiffMeasure2.BackColor == System.Drawing.Color.Blue)
                    {
                        PlaySound("DINGDONG.wav");
                        BarcodePrint2();
                        Logger.LogOnce("[2] 바코드 출력");
                        CloseMeasureLog2();
                        GlobalValues.OkCount++;
                        GlobalValues.TotalCount++;
                        lbOkCount.Text = GlobalValues.OkCount.ToString();
                        lbNGCount.Text = (GlobalValues.TotalCount - GlobalValues.OkCount).ToString();
                        lbTotalCount.Text = GlobalValues.TotalCount.ToString();
                        GlobalValues.SaveCounts();
                    }
                    else
                    {
                        CloseMeasureLog2();
                        BarcodePrintNg2();
                        PlaySound("NG.wav");
                        GlobalValues.TotalCount++;
                        lbOkCount.Text = GlobalValues.OkCount.ToString();
                        lbNGCount.Text = (GlobalValues.TotalCount - GlobalValues.OkCount).ToString();
                        lbTotalCount.Text = GlobalValues.TotalCount.ToString();
                        GlobalValues.SaveCounts();
                    }
                    wStep2 = 51;
                    break;

                case 51:
                    if (tmrWatch2.ElapsedMilliseconds > 1000)
                    {
                        wStep2 = 0;
                        _lever41Delay2 = false;
                        _alarmRetryCount2 = 0;
                        _alarmAtStep2 = 0;
                    }
                    break;

                case 99: // 서보 알람 3회 초과 정지 — 리셋 전까지 대기
                    break;

            }

        }


