        private CsvRawSaver _csv1 = new CsvRawSaver(4096);
        private CsvRawSaver _csv2 = new CsvRawSaver(4096);
        private string tmpsave1;
        private string tmpsave2;

        private void workTimer1_Tick(object sender, EventArgs e)
        {
            lbStep1.Text = $"[{wStep1.ToString()}][{wRstStep1.ToString()}]";

            if (PLCData1.PlcValueBit[0, 1] == true && wRstStep1 == 0) //리셋 스위치
            {
                wRstStep1 = 0.1;
            }

            switch (wRstStep1)
            {
                case 0:
                    break;

                case 0.1:
                    wStep1 = 0;
                    _lever41Delay1 = false;
                    _alarmRetryCount1 = 0;
                    _alarmAtStep1 = 0;
                    tmrRstWatch1.Restart();
                    wRstStep1 = 0.2;
                    break;

                case 0.2:
                    if (PLCData1.PlcValueBit[0, 1] == true)
                    {
                        if (tmrRstWatch1.ElapsedMilliseconds > 1000)
                        {
                            PLCData1.FlagRecvAll = true;
                            Logger.LogOnce("[1] 리셋 조건 발동");
                            wRstStep1 = 1;
                        }
                    }
                    else
                    {
                        wRstStep1 = 0;
                    }
                    break;

                case 1: //모든 시그널 클리어
                    for (int word = 0; word <= 7; word++)
                    {
                        for (int bit = 0; bit <= 15; bit++)
                        {
                            PLCData1.SetPlcBit(word, bit, false);
                        }
                    }
                    for (int bit = 0; bit <= 15; bit++)
                    {
                        PLCData1.SetPlcBit(9, bit, false);
                    }
                    for (int bit = 0; bit <= 15; bit++)
                    {
                        PLCData1.SetPlcBit(11, bit, false);
                    }
                    for (int bit = 0; bit <= 15; bit++)
                    {
                        PLCData1.SetPlcBit(12, bit, false);
                    }
                    for (int bit = 0; bit <= 15; bit++)
                    {
                        PLCData1.SetPlcBit(13, bit, false);
                    }
                    wRstStep1++;
                    break;

                case 2:
                    PLCData1.SetPlcBit(9, 1, false);
                    PLCData1.SetPlcBit(9, 2, false);
                    PLCData1.SetPlcBit(4, 8, true); //클램프 상승 지령 D4004.8
                    PLCData1.SetPlcBit(4, 10, true); //클램프 후진
                    PLCData1.SetPlcBit(4, 12, true); //LVDT 후진 지령 D4004.12
                    tmrWatch1.Restart();
                    wRstStep1++;
                    break;

                case 3:
                    if (PLCData1.PlcValueBit[0, 6] == true)
                    {
                        PLCData1.SetPlcBit(4, 8, false); //클램프 상승 지령 D4004.8
                    }
                    if (PLCData1.PlcValueBit[0, 9] == true)
                    {
                        PLCData1.SetPlcBit(4, 10, false); //클램프 후진 D4000.9
                    }
                    if (PLCData1.PlcValueBit[0, 10] == true)
                    {
                        PLCData1.SetPlcBit(4, 12, false); //LVDT 후진 지령 D4004.12 D4000.10
                    }
                    if (PLCData1.PlcValueBit[0, 6] == true &&
                        PLCData1.PlcValueBit[0, 9] == true &&
                        PLCData1.PlcValueBit[0, 10] == true)
                    {
                        tmrWatch1.Stop();
                        wRstStep1++;
                    }
                    break;

                case 4:
                    PLCData1.SetPlcBit(9, 9, true); //1축 서보 온
                    PLCData1.SetPlcBit(11, 9, true);//2축 서보 온
                    PLCData1.SetPlcBit(9, 3, true); //1축 알람 리셋
                    PLCData1.SetPlcBit(11, 3, true);//2축 알람 리셋
                    PLCData1.SetPlcBit(9, 6, true); //1축 수동 ON
                    PLCData1.SetPlcBit(11, 6, true);//2축 수동 ON                 
                    PLCData1.SetPlcBit(9, 5, false); //1축 자동 OFF
                    PLCData1.SetPlcBit(11, 5, false);//2축 자동 OFF                    
                    wRstStep1++;
                    break;

                case 5:
                    if (PLCData1.PlcValueBit[8, 1] == false && PLCData1.PlcValueBit[10, 1] == false &&
                        PLCData1.PlcValueBit[8, 7] == true && PLCData1.PlcValueBit[10, 7] == true &&
                        PLCData1.PlcValueBit[8, 4] == true && PLCData1.PlcValueBit[10, 4] == true)
                    {
                        wRstStep1++;
                    }
                    break;

                case 6:
                    PLCData1.SetPlcBit(9, 1, true); //1축 CCW
                    PLCData1.SetPlcBit(11, 1, true);//2축 CCW
                    tmrWatch1.Restart();
                    PLCData1.Servo1JogSpd = 1000;
                    PLCData1.ServoSet();
                    wRstStep1++;
                    break;

                case 7:
                    if (tmrWatch1.ElapsedMilliseconds > 1000)
                    {
                        PLCData1.SetPlcBit(9, 1, false); //1축 CCW
                        PLCData1.SetPlcBit(11, 1, false);//2축 CCW
                        tmrWatch1.Stop();
                        wRstStep1++;
                    }
                    break;

                case 8:
                    if (PLCData1.PlcValueBit[9, 1] == false && PLCData1.PlcValueBit[11, 1] == false)
                    {
                        PLCData1.SetPlcBit(9, 4, true); //1축 홈 ON 
                        tmrWatch1.Restart();
                        wRstStep1 = 8.1;
                    }
                    break;

                case 8.1:
                    if (tmrWatch1.ElapsedMilliseconds > 500)
                    {
                        tmrWatch1.Stop();
                        PLCData1.SetPlcBit(9, 4, false); //1축 홈 OFF                                          
                        wRstStep1 = 9;
                    }
                    break;


                case 9:
                    if (PLCData1.PlcValueBit[8, 12] == true) // 1축 홈포지션 완료
                    {
                        PLCData1.SetPlcBit(9, 4, false); //1축 홈 OFF
                        tmrRstWatch1.Restart();
                        wRstStep1 = 9.1;
                    }
                    break;

                case 9.1:
                    if (tmrRstWatch1.ElapsedMilliseconds > 500)
                    {
                        tmrRstWatch1.Stop();
                        wRstStep1 = 10;
                    }
                    break;

                case 10:

                    PLCData1.SetPlcBit(11, 4, true); //2축 홈 ON
                    tmrRstWatch1.Restart();
                    wRstStep1 = 10.1;
                    break;

                case 10.1:
                    if (tmrRstWatch1.ElapsedMilliseconds > 500)
                    {
                        PLCData1.SetPlcBit(11, 4, false); //2축 홈 OFF
                        tmrRstWatch1.Stop();
                        wRstStep1 = 11;
                    }
                    break;

                case 11:
                    if (PLCData1.PlcValueBit[10, 12] == true) // 2축 홈포지션 완료
                    {
                        PLCData1.SetPlcBit(11, 4, false); //2축 홈 OFF
                        tmrRstWatch1.Restart();
                        wRstStep1 = 11.1;
                    }
                    break;

                case 11.1:
                    if (tmrRstWatch1.ElapsedMilliseconds > 1500)
                    {
                        wRstStep1 = 12;
                    }
                    break;

                case 12:
                    PLCData1.SetPlcBit(9, 6, false); //1축 수동 OFF
                    PLCData1.SetPlcBit(11, 6, false); //2축 수동 OFF
                    PLCData1.SetPlcBit(9, 5, true); //1축 자동 ON
                    PLCData1.SetPlcBit(11, 5, true); //1축 자동 ON
                    wRstStep1++;
                    break;

                case 13:
                    if (PLCData1.PlcValueBit[8, 3] == true && PLCData1.PlcValueBit[10, 3] == true) //자동 
                    {
                        PLCData1.SetPlcBit(12, 0, true); //1축 1번 포지션ㄱㄱ
                        wRstStep1++;
                    }
                    break;

                case 14:
                    if (PLCData1.PlcValueBit[14, 0] == true && PLCData1.PlcValueBit[12, 0] == true) //1축 1번 완료 AND 명령 동시 ON
                    {
                        PLCData1.SetPlcBit(12, 0, false);
                        wRstStep1++;
                    }
                    break;

                case 15:
                    PLCData1.SetPlcBit(13, 0, true); //2축 1번 포지션ㄱㄱ
                    wRstStep1++;
                    break;

                case 16:
                    if (PLCData1.PlcValueBit[15, 0] == true && PLCData1.PlcValueBit[13, 0] == true) //2축 1번 완료 AND 명령 동시 ON
                    {
                        PLCData1.SetPlcBit(13, 0, false);
                        wRstStep1++;
                    }
                    break;

                case 17:
                    InitControl1();
                    PLCData1.FlagRecvAll = false;
                    wRstStep1 = 0;
                    Logger.LogOnce("[1] 리셋 완료");
                    break;

            }

            switch (wStep1)
            {
                case 0:

                    if (MeasureData1.TargetScan == "0")
                    {
                        if (PLCData1.PlcValueBit[0, 0] == true) //작업 시작
                        {
                            Logger.LogOnce("[1] 작업 시작(바코드 미사용)");
                            string tmppart = lbLPartNo1.Text;
                            string tmpbarcode = lbBarcode1.Text;
                            InitControl1();
                            lbLPartNo1.Text = tmppart;
                            lbBarcode1.Text = tmpbarcode;
                            lbReclFwdSpec1.Text = $"{MeasureData1.ReclineForwardTorqueMin.ToString()} ~ {MeasureData1.ReclineForwardTorqueMax.ToString()} Nm";
                            lbReclBwdSpec1.Text = $"{MeasureData1.ReclineForwardTorqueMin.ToString()} ~ {MeasureData1.ReclineForwardTorqueMax.ToString()} Nm";
                            lbLeverSpec1.Text = $"{MeasureData1.LeverTorqueMin.ToString()} ~ {MeasureData1.LeverTorqueMax.ToString()} Nm";

                            DiffSpec1.Text = $"{MeasureData1.SpecDiff.ToString()}";

                            PLCData1.SetPlcBit(4, 9, true); //클램프 하강 지령 D4004.9
                            Logger.LogOnce("[1] 클램프 하강 시작");
                            tmrWatch1.Restart();
                            PLCData1.FlagRecvAll = false;
                            wStep1++;
                        }
                    }
                    else
                    {
                        if (PLCData1.PlcValueBit[0, 0] == true && lbLPartNo1.Text != "" && lbBarcode1.BackColor == System.Drawing.Color.Blue) //작업 시작
                        {
                            Logger.LogOnce("[1] 작업 시작(바코드 사용)");
                            string tmppart = lbLPartNo1.Text;
                            string tmpbarcode = lbBarcode1.Text;
                            InitControl1();
                            lbLPartNo1.Text = tmppart;
                            lbBarcode1.Text = tmpbarcode;
                            lbReclFwdSpec1.Text = $"{MeasureData1.ReclineForwardTorqueMin.ToString()} ~ {MeasureData1.ReclineForwardTorqueMax.ToString()} Nm";
                            lbReclBwdSpec1.Text = $"{MeasureData1.ReclineForwardTorqueMin.ToString()} ~ {MeasureData1.ReclineForwardTorqueMax.ToString()} Nm";
                            lbLeverSpec1.Text = $"{MeasureData1.LeverTorqueMin.ToString()} ~ {MeasureData1.LeverTorqueMax.ToString()} Nm";

                            DiffSpec1.Text = $"{MeasureData1.SpecDiff.ToString()}";

                            PLCData1.SetPlcBit(4, 9, true); //클램프 하강 지령 D4004.9
                            Logger.LogOnce("[1] 클램프 하강 시작");
                            tmrWatch1.Restart();
                            PLCData1.FlagRecvAll = false;
                            wStep1++;
                        }
                    }
                    break;

                case 1:
                    if (PLCData1.PlcValueBit[0, 7] == true)
                    {
                        PLCData1.SetPlcBit(4, 9, false); //클램프 하강 지령 D4004.9
                        PLCData1.SetPlcBit(4, 11, true); //클램프 전진
                        wStep1++;
                    }
                    break;

                case 2:
                    if (PLCData1.PlcValueBit[0, 8] == true) //클램프 전진 완료 D4000.8
                    {
                        PLCData1.SetPlcBit(4, 11, false);
                        tmrWatch1.Restart();
                        wStep1++;
                    }
                    break;

                case 3:
                    ResetLeverTq1();
                    ResetReclTq1();
                    wStep1++;
                    tmrWatch1.Restart();
                    break;

                case 4:
                    if (tmrWatch1.ElapsedMilliseconds > 1000)
                    {
                        tmrWatch1.Stop();
                        wStep1++;
                    }
                    break;

                case 5:
                    StartMeasureLog1();
                    PLCData1.SetPlcBit(13, 1, true); //2축 2 포지션 이동 레버해제
                    measureStartTime1 = DateTime.Now;
                    timeList1.Clear();
                    valueList1.Clear();
                    tmrWatch1.Restart();
                    tmpMax1 = 0;
                    _csv1.Clear();
                    wStep1++;
                    break;

                case 6:

                    double elapsedSeconds = tmrWatch1.Elapsed.TotalSeconds;
                    if (tmpMax1 < MeasureData1.ValueLeverTq * MeasureData1.LeverTorqueTolerance) tmpMax1 = MeasureData1.ValueLeverTq * MeasureData1.LeverTorqueTolerance; //최대값 갱신                                                                   
                    ClassZedGraph.DrawGraph(PlotLever1, MeasureData1.ValueLeverTq * MeasureData1.LeverTorqueTolerance, elapsedSeconds);

                    _csv1.Add(elapsedSeconds, MeasureData1.ValueLeverTq * MeasureData1.LeverTorqueTolerance);

                    if (PLCData1.PlcValueBit[15, 1] == true && PLCData1.PlcValueBit[13, 1] == true) //2축 2 포지션 완료 AND 명령 동시 ON
                    {
                        tmpsave1 = DateTime.Now.ToString("yyMMddHHmmss") + Lot1 + lbLPartNo1.Text;
                        _csv1.Save($"{tmpsave1}_Lever_Torque");
                        lbLeverMeasure1.Text = tmpMax1.ToString("F1");
                        WriteMeasureLabelLog1("lbLeverMeasure1",
                            $"ValueLeverTq={MeasureData1.ValueLeverTq:F4}, LeverTorqueTolerance={MeasureData1.LeverTorqueTolerance:F4}",
                            "tmpMax1 = Max(ValueLeverTq * LeverTorqueTolerance) 측정구간 최대값",
                            tmpMax1.ToString("F1"));
                        PLCData1.SetPlcBit(13, 1, false);
                        wStep1++;
                    }
                    break;

                case 7:
                    JudgeAndSetLabel(MeasureData1.LeverTorqueMin, MeasureData1.LeverTorqueMax, tmpMax1, lbLeverMeasure1);
                    WriteMeasureLabelLog1("lbLeverMeasure1(Judge)", $"tmpMax1={tmpMax1:F4}, Min={MeasureData1.LeverTorqueMin}, Max={MeasureData1.LeverTorqueMax}", "합격(Blue)/불합격(Red) 판정", lbLeverMeasure1.Text);
                    wStep1++;
                    break;

                case 8:
                    if (MeasureData1.BurnishingCount > 0)
                    {
                        bCount1 = 0;
                        wStep1 = 8.1;
                    }
                    else
                    {
                        wStep1++;
                    }
                    break;

                case 8.1: //버니싱
                    PLCData1.SetPlcBit(12, 3, true);//1축 4 포지션
                    wStep1 = 8.2;
                    break;

                case 8.2:
                    if (PLCData1.PlcValueBit[14, 3] == true && PLCData1.PlcValueBit[12, 3] == true) //완료 AND 명령 동시 ON
                    {
                        PLCData1.SetPlcBit(12, 3, false);
                        wStep1 = 8.3;
                    }
                    break;

                case 8.3:
                    PLCData1.SetPlcBit(12, 4, true);//1축 5 포지션
                    wStep1 = 8.4;
                    break;

                case 8.4:
                    if (PLCData1.PlcValueBit[14, 4] == true && PLCData1.PlcValueBit[12, 4] == true) //완료 AND 명령 동시 ON
                    {
                        PLCData1.SetPlcBit(12, 4, false);
                        wStep1 = 8.5;
                    }
                    break;

                case 8.5:
                    bCount1++;
                    if (bCount1 >= MeasureData1.BurnishingCount)
                    {
                        wStep1 = 9;
                    }
                    else
                    {
                        wStep1 = 8.1; //다시 버니싱
                    }
                    break;

                case 9: // 토크 리셋
                    ResetReclTq1();
                    tmrWatch1.Restart();
                    wStep1++;
                    break;

                case 10:
                    if (tmrWatch1.ElapsedMilliseconds > 1000)
                    {
                        tmrWatch1.Stop();
                        wStep1++;
                    }
                    break;

                case 11:
                    PLCData1.SetPlcBit(12, 1, true); //1축 2포지션 이동 
                    measureStartTime1 = DateTime.Now;
                    timeList1.Clear();
                    valueList1.Clear();
                    tmrWatch1.Restart();
                    tmpMax1 = 0;
                    wStep1++;
                    _csv1.Clear();
                    break;

                case 12:

                    elapsedSeconds = tmrWatch1.Elapsed.TotalSeconds;
                    double tol = MeasureData1.ReclineFwdTorqueTolerance;
                    if (elapsedSeconds > 1)
                    {
                        if (tmpMax1 < Math.Abs(MeasureData1.ValueReclTq * tol)) tmpMax1 = Math.Abs(MeasureData1.ValueReclTq) * tol; //최대값 갱신 
                        ClassZedGraph.DrawGraph(PlotReclFwd1, Math.Abs(MeasureData1.ValueReclTq) * tol, elapsedSeconds);
                    }
                    _csv1.Add(elapsedSeconds, Math.Abs(MeasureData1.ValueReclTq * tol));
                    if (PLCData1.PlcValueBit[14, 1] == true && PLCData1.PlcValueBit[12, 1] == true) //1축 2 포지션 완료 AND 명령 동시 ON
                    {
                        lbReclFwdMeasure1.Text = tmpMax1.ToString("F1");
                        WriteMeasureLabelLog1("lbReclFwdMeasure1",
                            $"ValueReclTq={MeasureData1.ValueReclTq:F4}, ReclineFwdTorqueTolerance={MeasureData1.ReclineFwdTorqueTolerance:F4}",
                            "tmpMax1 = Max(Abs(ValueReclTq * ReclineFwdTorqueTolerance))",
                            tmpMax1.ToString("F1"));
                        PLCData1.SetPlcBit(12, 1, false);
                        wStep1++;
                    }
                    break;

                case 13:
                    _csv1.Save($"{tmpsave1}_Fwd_Torque");
                    JudgeAndSetLabel(MeasureData1.ReclineForwardTorqueMin, MeasureData1.ReclineForwardTorqueMax, tmpMax1, lbReclFwdMeasure1);
                    WriteMeasureLabelLog1("lbReclFwdMeasure1(Judge)", $"tmpMax1={tmpMax1:F4}, Min={MeasureData1.ReclineForwardTorqueMin}, Max={MeasureData1.ReclineForwardTorqueMax}", "합격/불합격 판정", lbReclFwdMeasure1.Text);
                    wStep1++;
                    break;

                case 14:
                    PLCData1.SetPlcBit(12, 2, true); //1축 3포지션 이동 
                    measureStartTime1 = DateTime.Now;
                    timeList1.Clear();
                    valueList1.Clear();
                    tmrWatch1.Restart();
                    tmpMax1 = 0;
                    wStep1++;
                    _csv1.Clear();
                    break;

                case 15:

                    elapsedSeconds = tmrWatch1.Elapsed.TotalSeconds;
                    tol = MeasureData1.ReclineBwdTorqueTolerance;
                    if (elapsedSeconds > 1)
                    {
                        if (tmpMax1 < Math.Abs(MeasureData1.ValueReclTq) * tol) tmpMax1 = Math.Abs(MeasureData1.ValueReclTq) * tol; //최대값 갱신 
                        ClassZedGraph.DrawGraph(PlotReclBwd1, Math.Abs(MeasureData1.ValueReclTq) * tol, elapsedSeconds);
                    }

                    _csv1.Add(elapsedSeconds, Math.Abs(MeasureData1.ValueReclTq) * tol);

                    if (PLCData1.PlcValueBit[14, 2] == true && PLCData1.PlcValueBit[12, 2] == true) //1축 3포지션 완료 AND 명령 동시 ON
                    {
                        lbReclBwdMeasure1.Text = tmpMax1.ToString("F1");
                        WriteMeasureLabelLog1("lbReclBwdMeasure1",
                            $"ValueReclTq={MeasureData1.ValueReclTq:F4}, ReclineBwdTorqueTolerance={MeasureData1.ReclineBwdTorqueTolerance:F4}",
                            "tmpMax1 = Max(Abs(ValueReclTq) * ReclineBwdTorqueTolerance)",
                            tmpMax1.ToString("F1"));
                        PLCData1.SetPlcBit(12, 2, false);
                        wStep1++;
                    }
                    break;

                case 16:
                    _csv1.Save($"{tmpsave1}_Bwd_Torque");
                    JudgeAndSetLabel(MeasureData1.ReclineBackwardTorqueMin, MeasureData1.ReclineBackwardTorqueMax, tmpMax1, lbReclBwdMeasure1);
                    WriteMeasureLabelLog1("lbReclBwdMeasure1(Judge)", $"tmpMax1={tmpMax1:F4}, Min={MeasureData1.ReclineBackwardTorqueMin}, Max={MeasureData1.ReclineBackwardTorqueMax}", "합격/불합격 판정", lbReclBwdMeasure1.Text);
                    wStep1++;
                    break;


                case 17:
                    Logger.LogOnce("[1] 1축 1번 포지션 이동 시작");
                    PLCData1.SetPlcBit(13, 0, true); //2축 1번 포지션 이동 레버해제                    
                    wStep1++;
                    break;

                case 18:
                    if (PLCData1.PlcValueBit[15, 0] == true && PLCData1.PlcValueBit[13, 0] == true) //2축 1번 완료 AND 명령 동시 ON
                    {
                        PLCData1.SetPlcBit(13, 0, false);
                        wStep1++;
                    }
                    break;

                case 19: //LVDT 전진
                    PLCData1.SetPlcBit(4, 13, true); //LVDT 전진 지령 D4004.13
                    tmrWatch1.Restart();
                    wStep1++;
                    break;

                case 20:
                    if (tmrWatch1.Elapsed.TotalSeconds > 3 ||
                        PLCData1.PlcValueBit[0, 11] == true ||  // LVDT 전진
                        PLCData1.PlcValueBit[0, 12] == true ||  // 가이드 전진 1
                        PLCData1.PlcValueBit[0, 14] == true ||  // 가이드 전진 1
                        PLCData1.PlcValueBit[0, 15] == true)    // 가이드 전진 2
                    {
                        PLCData1.SetPlcBit(4, 13, false); //LVDT 전진 지령 OFF D4004.13
                        tmrWatch1.Stop();
                        wStep1++;
                    }
                    break;

                case 21:
                    ResetReclTq1();
                    tmrWatch1.Restart();
                    wStep1++;
                    break;

                case 22:
                    if (tmrWatch1.Elapsed.TotalSeconds > 2)
                    {
                        DiffStartTmp1_1 = MeasureData1.ValueLvdt;
                        StartDebugLog1(); // 디버그 로그 시작 (바탕화면)
                        WriteDebugLog1(22, "LVDT_BASE_SET");
                        tmrWatch1.Stop();
                        wStep1++;
                    }
                    break;

                case 23:

                    tmpBeforeSpeed1 = PLCData1.Servo1JogSpd;
                    PLCData1.FlagRecvAll = true;
                    PLCData1.Servo1JogSpd = PLCData1.DiffSpeed;
                    PLCData1.ServoSet();
                    wStep1++;
                    break;

                case 23.1:

                    if (PLCData1.PlcValue[5002] == PLCData1.DiffSpeed)
                    {
                        PLCData1.FlagRecvAll = false;
                        wStep1 = 24;
                    }
                    break;

                case 24:
                    PLCData1.SetPlcBit(9, 5, false); //1축 자동 OFF
                    PLCData1.SetPlcBit(11, 5, false); //2축 자동 OFF
                    PLCData1.SetPlcBit(9, 6, true); //1축 수동 ON
                    PLCData1.SetPlcBit(11, 6, true); //2축 수동 ON
                    wStep1++;
                    break;

                case 25:
                    if (PLCData1.PlcValueBit[8, 4] == true && PLCData1.PlcValueBit[10, 4] == true) //수동 확인
                    {
                        timeList1.Clear();
                        valueList1.Clear();
                        DiffFwdTmp1 = 0;
                        DiffBwdTmp1 = 0;
                        wStep1++;
                    }
