                string line = string.Format(
                    "{0},{1},{2},{3:F4},{4:F4},{5:F4},{6:F4},{7:F4},{8:F4},{9:F4},{10},{11},{12:F4},{13:F4},{14:F4},{15:F4},{16:F4},{17:F4},{18}",
