        }

        private void WriteDebugLog2(double step, string phase, double graphX = double.NaN, double graphY = double.NaN)
        {
            try
            {
                if (debugLogWriter2 == null) return;

                double rawLvdt = MeasureData2.ValueLvdt;
                double rawTorque = MeasureData2.ValueReclTq;
                double elapsed = tmrWatch2.IsRunning ? tmrWatch2.ElapsedMilliseconds : -1;

                string line = string.Format(
                    "{0},{1},{2},{3:F4},{4:F4},{5:F4},{6:F4},{7:F4},{8:F4},{9:F4},{10},{11},{12:F4},{13:F4},{14:F4},{15:F4},{16:F4},{17:F4},{18}",
                    DateTime.Now.ToString("HH:mm:ss.fff"),
                    step,
                    phase,
                    rawLvdt,
                    rawTorque,
                    DiffStartTmp2_1,
                    diff2CwStartLvdt,
                    tmpNum2,
                    1.0, // ScaleFwd (고정)
                    1.0, // ScaleBwd (고정)
                    double.IsNaN(graphX) ? "" : graphX.ToString("F4"),
                    double.IsNaN(graphY) ? "" : graphY.ToString("F4"),
                    diff2BlackEndX,
                    diff2BlackEndY,
                    diff2LastX,
                    diff2LastY,
                    MeasureData2.DiffLimitFwd,
                    MeasureData2.DiffLimitBwd,
                    elapsed
                );
                debugLogWriter2.WriteLine(line);
                debugLogWriter2.Flush();
            }
            catch { }
        }

        private void CloseDebugLog2()
        {
            try
            {
                if (debugLogWriter2 != null)
                {
                    debugLogWriter2.Close();
                    debugLogWriter2.Dispose();
                    debugLogWriter2 = null;
                    Logger.LogOnce("[DEBUG] 2축 디버그 로그 저장 완료");
                }
            }
            catch { }
        }

        /// <summary>
        /// 유격 로그 시작 (OUTER/2축)
        /// </summary>
        private void StartDiffLog2()
        {
            try
            {
                string logDir = Path.Combine(Application.StartupPath, "DiffLog");
                if (!Directory.Exists(logDir))
                {
                    Directory.CreateDirectory(logDir);
                }

                string fileName = DateTime.Now.ToString("yyyyMMdd_HHmmss") + "_OUTER.csv";
                diffLogPath2 = Path.Combine(logDir, fileName);

                diffLogWriter2 = new StreamWriter(diffLogPath2, false, Encoding.UTF8);
                diffLogWriter2.WriteLine("Time,Step,LVDT,Torque,X,Y,Direction");
                Logger.LogOnce("[2] 유격 로그 시작", $"[2] 유격 로그 시작: {diffLogPath2}");
            }
            catch (Exception ex)
            {
                Logger.LogOnce("[2] 유격 로그 시작 오류", $"[2] 유격 로그 시작 오류: {ex.Message}");
            }
        }

        /// <summary>
        /// 유격 로그 기록 (OUTER/2축)
        /// </summary>
        private void WriteDiffLog2(double step, string direction)
        {
            try
            {
                if (diffLogWriter2 != null)
                {
                    double lvdt = MeasureData2.ValueLvdt;
                    double torque = MeasureData2.ValueReclTq;
                    double x = lvdt - DiffStartTmp2_1;
                    double y = tmpNum2 * -1 * torque; // 그래프에 그려지는 Y값

                    string line = $"{DateTime.Now:HH:mm:ss.fff},{step},{lvdt:F4},{torque:F4},{x:F4},{y:F4},{direction}";
                    diffLogWriter2.WriteLine(line);
                    diffLogWriter2.Flush();
                }
            }
            catch (Exception ex)
            {
                Logger.LogOnce("[2] 유격 로그 기록 오류", $"[2] 유격 로그 기록 오류: {ex.Message}");
            }
        }

        /// <summary>
        /// 유격 로그 종료 (OUTER/2축)
        /// </summary>
        private void CloseDiffLog2()
        {
            try
            {
                if (diffLogWriter2 != null)
                {
                    diffLogWriter2.Close();
                    diffLogWriter2.Dispose();
                    diffLogWriter2 = null;
                    Logger.LogOnce("[2] 유격 로그 저장 완료", $"[2] 유격 로그 저장 완료: {diffLogPath2}");
                }
            }
            catch (Exception ex)
            {
                Logger.LogOnce("[2] 유격 로그 종료 오류", $"[2] 유격 로그 종료 오류: {ex.Message}");
            }
        }

        #endregion
    }

}

