    TryReconnectPort(SerialLeverTq1, GlobalValues.LeverTq1Port, 38400, "SerialLeverTq1");
    TryReconnectPort(SerialLeverTq2, GlobalValues.LeverTq2Port, 38400, "SerialLeverTq2");
