    TryReconnectPort(SerialReclTq2, GlobalValues.ReclTq2Port, 38400, "SerialReclTq2");

    RequestTorqueAll();

    // 4개 포트 파싱 미갱신 5초 경고
    var now = DateTime.Now;
    CheckParseTimeout(now, "ReclTq1", _lastReclTq1Parse, _lastReclTq1Rx, ref _reclTq1WarningSent);
    CheckParseTimeout(now, "ReclTq2", _lastReclTq2Parse, _lastReclTq2Rx, ref _reclTq2WarningSent);
    CheckParseLeverTimeout(now, "LeverTq1", _lastLeverTq1Parse, ref _leverTq1RetryCount);
    CheckParseLeverTimeout(now, "LeverTq2", _lastLeverTq2Parse, ref _leverTq2RetryCount);
}

// 포트 끊김 시 자동 재연결
private void TryReconnectPort(SerialPort sp, string portName, int baudRate, string label)
{
    try
    {
        if (!sp.IsOpen && !string.IsNullOrEmpty(portName))
        {
            sp.PortName = portName;
            sp.BaudRate = baudRate;
            sp.DataBits = 8;
            sp.Open();
            Logger.LogOnce($"재연결 OK {label}", $"[재연결] {label} ({portName}): 재연결 성공");
        }
    }
    catch { } // 포트 아직 불가 — 다음 틱에서 재시도
}

// ReclTq 파싱 미갱신 경고
private void CheckParseTimeout(DateTime now, string name, DateTime lastParse, DateTime lastRx, ref bool warningSent)
{
    if (lastParse != DateTime.MinValue && (now - lastParse).TotalSeconds >= 5 && !warningSent)
    {
        warningSent = true;
        if ((now - lastRx).TotalSeconds < 5)
            Logger.Log($"[토크진단] {name} 파싱 실패 5초 초과 (수신은 있음)");
        else
            Logger.Log($"[토크진단] {name} 수신 없음 5초 초과");
    }
}

// LeverTq 파싱 미갱신 경고
private void CheckParseLeverTimeout(DateTime now, string name, DateTime lastParse, ref int retryCount)
{
    if (lastParse != DateTime.MinValue && (now - lastParse).TotalSeconds >= 5 && retryCount == 0)
    {
        retryCount = 1; // 1회만 경고
        Logger.Log($"[토크진단] {name} 파싱 없음 5초 초과");
    }
}

