                case 25:
                    if (PLCData1.PlcValueBit[8, 4] == true && PLCData1.PlcValueBit[10, 4] == true) //수동 확인
                    {
                        timeList1.Clear();
                        valueList1.Clear();
                        DiffFwdTmp1 = 0;
                        DiffBwdTmp1 = 0;
                        wStep1++;
                    }
                    break;

                case 26:
                    StartDiffLog1(); // 유격 로그 시작
                    WriteDiffLog1(26, "CCW_START"); // 시작 로그
