                    // PLCData1.FlagRecvAll = true;
                    // PLCData1.ServoSet();
                    WriteDiffLog1(37, $"SPEED_KEEP_DIFF: DiffSpeed={PLCData1.DiffSpeed}, CurrentSpd={PLCData1.Servo1JogSpd}");
                    WriteDebugLog1(37, $"RESULT:FwdDiff={MaxDiffFwd1:F4},BwdDiff={MaxDiffBwd1:F4},fval={fval:F4},bval={bval:F4}");
                    wStep1 = 37.1;
                    break;

                case 37.1: // 알람 확인 및 리셋 (무조건 리셋 후 진행) — 3회 재시도
                    if (_alarmRetryCount1 >= 3)
                    {
                        Logger.LogOnce("[1] 서보 알람 3회 초과", "[1] 서보 알람 3회 초과 — step 37.1(CW 완료 후 알람 리셋)에서 정지. 설비 점검 필요.");
                        CloseDiffLog1();
                        CloseDebugLog1();
                        wStep1 = 99;
                    }
                    else
                    {
                        _alarmAtStep1 = 37.1;
                        _alarmRetryCount1++;
                        WriteDiffLog1(37.1, "ALARM_CHECK");
                        PLCData1.SetPlcBit(9, 7, false); //1축 수동 정지 지령 해제
                        PLCData1.SetPlcBit(9, 3, true); //1축 알람 리셋
                        PLCData1.SetPlcBit(11, 3, true); //2축 알람 리셋
                        WriteDiffLog1(37.1, "ALARM_RESET_ON");
                        tmrWatch1.Restart();
                        wStep1 = 37.2;
                    }
                    break;

                case 37.2: // 알람 리셋 대기 (1초)
                    if (tmrWatch1.ElapsedMilliseconds > 1000)
                    {
                        tmrWatch1.Stop();
                        PLCData1.SetPlcBit(9, 3, false); //1축 알람 리셋 OFF
                        PLCData1.SetPlcBit(11, 3, false); //2축 알람 리셋 OFF
                        WriteDiffLog1(37.2, "ALARM_RESET_OFF");
                        wStep1 = 37.3;
                    }
                    break;

                case 37.3: // 알람 해제 확인
                    if (PLCData1.PlcValueBit[8, 1] == false && PLCData1.PlcValueBit[10, 1] == false)
                    {
                        _alarmRetryCount1 = 0; // 복구 성공 시 재시도 카운트 리셋
                        WriteDiffLog1(37.3, "ALARM_CLEARED");
                        tmrWatch1.Restart();
                        wStep1 = 37.4; // 딜레이 후 CCW 복귀
                    }
                    else
                    {
                        WriteDiffLog1(37.3, "ALARM_STILL_ON");
                        if (_alarmRetryCount1 >= 3)
                        {
                            Logger.LogOnce("[1] 서보 알람 3회 초과", "[1] 서보 알람 3회 초과 — step 37.1(CW 완료 후 알람 리셋)에서 정지. 설비 점검 필요.");
                            CloseDiffLog1();
                            CloseDebugLog1();
                            wStep1 = 99;
                        }
                        else
                            wStep1 = 37.1; // 알람 아직 있으면 다시 리셋
                    }
                    break;

                case 37.4: // CCW 복귀 전 딜레이 (1초 대기)
                    WriteDiffLog1(37.4, "CCW_RETURN_DELAY");
                    if (tmrWatch1.ElapsedMilliseconds > 1000)
                    {
                        WriteDiffLog1(37.4, "CCW_RETURN_DELAY_END");
                        wStep1 = 37.5;
                    }
                    break;

                case 37.5: // CCW 복귀 측정 시작 (토크 0까지)
                    WriteDiffLog1(37.5, "CCW_RETURN_START");
                    WriteDebugLog1(37.5, "CCW_RETURN_START");
                    PLCData1.SetPlcBit(9, 6, true);  // 1축 수동 ON (필수: 수동 모드에서만 CCW/CW 동작)
                    WriteDiffLog1(37.5, "PLC_MANUAL_ON");
                    PLCData1.SetPlcBit(9, 7, false); // 1축 수동 정지 지령 해제
                    WriteDiffLog1(37.5, "PLC_STOP_OFF");
                    PLCData1.SetPlcBit(9, 1, false); // 1축 CW OFF (혹시 켜져있으면 끄기)
                    WriteDiffLog1(37.5, "PLC_CW_OFF");
                    PLCData1.SetPlcBit(9, 2, true);  // 1축 CCW ON (9,2가 CCW, 9,1이 CW)
                    WriteDiffLog1(37.5, "PLC_CCW_ON");
                    // 복귀선 첫 점을 CW 마지막 좌표에 찍어서 연결
                    ClassZedGraph.DrawGraphLine(PlotDiff1, diff1LastX, diff1LastY, 2);
                    tmrWatch1.Restart();
                    wStep1 = 37.6;
                    break;

                case 37.6: // CCW 복귀 - 토크 0까지 이동
                    {
                        double xReturn = diff1BlackEndX + (MeasureData1.ValueLvdt - diff1CwStartLvdt);
                        double yReturn = tmpNum1 * MeasureData1.ValueReclTq;

                        // 토크가 음수(CW방향)일 때만 복귀 곡선 그리기
                        if (yReturn <= 0)
                        {
                            ClassZedGraph.DrawGraphLine(PlotDiff1, xReturn, yReturn, 2); // 파랑 선 (복귀)
                            diff1LastX = xReturn;
                            diff1LastY = yReturn;
                        }
                        WriteDiffLog1(37.6, "CCW_RETURN_MEASURE");
                        WriteDebugLog1(37.6, "CCW_RETURN_MEASURE", xReturn, yReturn);

                        // 토크 60 Nm 초과 시 강제 정지 (서보 과부하 방지)
                        if (Math.Abs(MeasureData1.ValueReclTq) > 60)
                        {
                            _alarmRetryCount1 = 0;
                            Logger.LogOnce("[1] CCW 복귀 중 토크 60 Nm 초과 - 강제 정지");
                            WriteDiffLog1(37.6, "CCW_RETURN_TORQUE_OVER_60");
                            WriteDebugLog1(37.6, "CCW_RETURN_TORQUE_OVER_60", xReturn, yReturn);
                            PLCData1.SetPlcBit(9, 2, false); // CCW OFF
                            PLCData1.SetPlcBit(9, 7, true);  // 수동 정지
                            CloseDiffLog1();
                            CloseDebugLog1();
                            wStep1 = 38;
                        }
                        // 토크가 0 근처에 도달하면 완료
                        else if (Math.Abs(MeasureData1.ValueReclTq) < 0.5)
                        {
                            _alarmRetryCount1 = 0; // 정상 완료 시 재시도 카운트 리셋
                            // 그래프 원점(0,0)으로 루프 닫기
                            ClassZedGraph.DrawGraphLine(PlotDiff1, 0, 0, 2);
                            WriteDiffLog1(37.6, "CCW_RETURN_END");
                            PLCData1.SetPlcBit(9, 2, false); // CCW OFF
                            WriteDiffLog1(37.6, "PLC_CCW_OFF");
                            PLCData1.SetPlcBit(9, 7, true);  // 수동 정지
                            WriteDiffLog1(37.6, "PLC_STOP_ON");
                            CloseDiffLog1();
                            CloseDebugLog1();
                            wStep1 = 38;
                        }
                        // 타임아웃: 15초 내 원점 미도달 시 강제 완료
                        else if (tmrWatch1.Elapsed.TotalSeconds > 15)
                        {
                            _alarmRetryCount1 = 0;
                            WriteDiffLog1(37.6, "CCW_RETURN_TIMEOUT");
                            WriteDebugLog1(37.6, "CCW_RETURN_TIMEOUT", xReturn, yReturn);
                            PLCData1.SetPlcBit(9, 2, false); // CCW OFF
                            PLCData1.SetPlcBit(9, 7, true);  // 수동 정지
                            CloseDiffLog1();
                            CloseDebugLog1();
                            wStep1 = 38;
                        }
                        // 서보 알람 시 자동 에러리셋 후 재시도 (최대 3회)
                        else if (PLCData1.PlcValueBit[8, 1] == true || PLCData1.PlcValueBit[10, 1] == true)
                        {
                            if (_alarmRetryCount1 >= 3)
                            {
                                Logger.LogOnce("[1] 서보 알람 3회 초과", "[1] 서보 알람 3회 초과 — step 37.6(CCW 복귀)에서 정지. 설비 점검 필요.");
                                CloseDiffLog1();
                                CloseDebugLog1();
                                wStep1 = 99;
                            }
                            else
                            {
                                _alarmAtStep1 = 37.6;
                                _alarmRetryCount1++;
                                Logger.LogOnce("[1] CCW 복귀 중 서보 알람 - 에러리셋");
                                WriteDiffLog1(37.6, "SERVO_ALARM_RESET");
                                PLCData1.SetPlcBit(9, 2, false); // CCW OFF
                                PLCData1.SetPlcBit(9, 7, false); // 수동 정지 해제
                                PLCData1.SetPlcBit(9, 3, true);  // 1축 알람 리셋
                                PLCData1.SetPlcBit(11, 3, true); // 2축 알람 리셋
                                tmrWatch1.Restart();
                                wStep1 = 37.61;
                            }
                        }
                    }
                    break;

                case 37.61: // 서보 알람 에러리셋 대기 — 알람 해제 시 진행, 최소 1초·최대 2초
                    bool alarmCleared1 = PLCData1.PlcValueBit[8, 1] == false && PLCData1.PlcValueBit[10, 1] == false;
                    bool minElapsed1 = tmrWatch1.ElapsedMilliseconds >= 1000; // 리셋 펄스 최소 1초
                    bool timeout1 = tmrWatch1.ElapsedMilliseconds > 2000;
                    if ((minElapsed1 && alarmCleared1) || timeout1)
                    {
                        if (timeout1 && !alarmCleared1)
                            Logger.LogOnce("[1] CCW 복귀 서보 알람 — 2초 내 미해제, 진행");
                        PLCData1.SetPlcBit(9, 3, false);  // 1축 알람 리셋 OFF
                        PLCData1.SetPlcBit(11, 3, false); // 2축 알람 리셋 OFF
                        PLCData1.SetPlcBit(9, 9, true);   // 1축 서보 온
                        PLCData1.SetPlcBit(11, 9, true);  // 2축 서보 온
                        CloseDiffLog1();
                        CloseDebugLog1();
                        wStep1 = 37.5; // CCW 복귀 재시도 (3회 초과 시 다음 37.6에서 99로 정지)
                    }
                    break;

                case 38:
                    // 속도 복원 (원래 속도로)
                    WriteDebugLog1(38, "MEASUREMENT_COMPLETE");
                    CloseDebugLog1(); // 디버그 로그 닫기
                    WriteDiffLog1(38, $"SPEED_RESTORE: BeforeSpeed={tmpBeforeSpeed1}, CurrentSpd={PLCData1.Servo1JogSpd}");
                    PLCData1.Servo1JogSpd = tmpBeforeSpeed1;
                    PLCData1.FlagRecvAll = true;
                    PLCData1.ServoSet();

                    PLCData1.SetPlcBit(9, 7, false); //1축 수동 정지 지령
                    PLCData1.SetPlcBit(9, 5, true); //1축 자동 ON
                    PLCData1.SetPlcBit(11, 5, true); //2축 자동 ON
                    PLCData1.SetPlcBit(9, 6, false); //1축 수동 OFF
                    PLCData1.SetPlcBit(11, 6, false); //2축 수동 OFF
                    _csv1.Save($"{tmpsave1}_Diff");
                    wStep1++;
                    break;

                case 39:
                    PLCData1.SetPlcBit(4, 12, true); //LVDT 후진 지령 D4004.12
                    wStep1++;
                    break;

                case 40:
                    if (PLCData1.PlcValueBit[0, 10] == true || PLCData1.PlcValueBit[0, 13] == true) // LVDT 후진, 가이드 후진 2
                    {
                        PLCData1.SetPlcBit(4, 12, false); //LVDT 후진 지령 D4004.12
                        PLCData1.FlagRecvAll = false;
                        wStep1++;
                    }
                    break;

                case 41:
                    if (!_lever41Delay1)
                    {
                        PLCData1.SetPlcBit(13, 1, true); //2축 2번 포지션,레버 해제
                        tmrWatch1.Restart();
                        _lever41Delay1 = true;
                    }
                    else if (tmrWatch1.ElapsedMilliseconds >= 2000)
                    {
                        _lever41Delay1 = false;
                        wStep1 = 42;
                    }
                    break;

                case 42:
                    bool complete15_1 = PLCData1.PlcValueBit[15, 1];
                    bool command13_1 = PLCData1.PlcValueBit[13, 1];
                    bool alarm8_1 = PLCData1.PlcValueBit[8, 1];
                    bool alarm10_1 = PLCData1.PlcValueBit[10, 1];
                    if (complete15_1 && command13_1) //완료 AND 명령 동시 ON
                    {
                        _alarmRetryCount1 = 0; // 레버 완료 시 재시도 카운트 리셋
                        Logger.LogOnce("[1] 레버 해제 완료");
                        PLCData1.SetPlcBit(13, 1, false); //레버 해제 완료
                        PLCData1.SetPlcBit(9, 3, true);   // 1축 에러 리셋
                        PLCData1.SetPlcBit(11, 3, true);  // 2축 에러 리셋
                        tmrWatch1.Restart();
                        wStep1 = 42.1;
                    }
                    else if (alarm8_1 || alarm10_1)
                    {
                        if (_alarmRetryCount1 >= 3)
                        {
                            Logger.LogOnce("[1] 서보 알람 3회 초과", "[1] 서보 알람 3회 초과 — step 42(레버 포지션 완료 대기)에서 정지. 설비 점검 필요.");
                            wStep1 = 99;
                        }
                        else
                        {
                            _alarmAtStep1 = 42;
                            _alarmRetryCount1++;
                            Logger.LogOnce("[1] step42 서보 알람 - 에러리셋 후 재시도");
                            PLCData1.SetPlcBit(13, 1, false);
                            PLCData1.SetPlcBit(9, 3, true);
                            PLCData1.SetPlcBit(11, 3, true);
                            tmrWatch1.Restart();
                            wStep1 = 42.1;
                        }
                    }
                    break;

                case 42.1: // 에러 리셋 후 서보 온까지 대기 (최소 1초·최대 2초)
                    bool alarmCleared42_1 = PLCData1.PlcValueBit[8, 1] == false && PLCData1.PlcValueBit[10, 1] == false;
                    bool minElapsed42_1 = tmrWatch1.ElapsedMilliseconds >= 1000;
                    bool timeout42_1 = tmrWatch1.ElapsedMilliseconds > 2000;
                    if ((minElapsed42_1 && alarmCleared42_1) || timeout42_1)
                    {
                        if (timeout42_1 && !alarmCleared42_1)
                            Logger.LogOnce("[1] step 42 에러리셋 — 2초 내 미해제, 진행");
                        PLCData1.SetPlcBit(9, 3, false);  // 1축 알람 리셋 OFF
                        PLCData1.SetPlcBit(11, 3, false); // 2축 알람 리셋 OFF
                        PLCData1.SetPlcBit(9, 9, true);   // 1축 서보 온
                        PLCData1.SetPlcBit(11, 9, true);  // 2축 서보 온
                        if (_alarmAtStep1 == 42)
                        {
                            _alarmAtStep1 = 0;
                            wStep1 = 41; // 레버 포지션 재시도
                        }
                        else
                            wStep1 = 43;
                    }
                    break;

                case 43:
                    Logger.LogOnce("[1] 1축 1번 포지션 이동 시작");
                    PLCData1.SetPlcBit(12, 0, true); //1축 1번 포지션
                    wStep1++;
                    break;

                case 44:
                    if (PLCData1.PlcValueBit[14, 0] == true && PLCData1.PlcValueBit[12, 0] == true) //완료 AND 명령 동시 ON
                    {
                        PLCData1.SetPlcBit(12, 0, false);
                        wStep1++;
                    }
                    break;

                case 45:
                    PLCData1.SetPlcBit(13, 0, true); //2축 1번 포지션,레버 원위치
                    wStep1++;
                    break;

                case 46:
                    if (PLCData1.PlcValueBit[15, 0] == true && PLCData1.PlcValueBit[13, 0] == true) //완료 AND 명령 동시 ON
                    {
                        PLCData1.SetPlcBit(13, 0, false); //레버 해제 완료
                        wStep1++;
                    }
                    break;

                case 47:

                    PLCData1.SetPlcBit(4, 8, true); //클램프 상승 지령 D4004.8
                    PLCData1.SetPlcBit(4, 10, true); //클램프 후진
                    tmrRstWatch1.Restart();
                    wStep1++;
                    break;

                case 48:
                    if (PLCData1.PlcValueBit[0, 6] == true) //클램프 상승
                    {
                        PLCData1.SetPlcBit(4, 8, false); //클램프 상승 지령 D4004.8
                    }
                    if (PLCData1.PlcValueBit[0, 9] == true) //클램프 후진 D4000.9
                    {
                        PLCData1.SetPlcBit(4, 10, false); //클램프 후진
                    }
                    if (PLCData1.PlcValueBit[0, 6] == true && PLCData1.PlcValueBit[0, 9] == true)
                    {
                        wStep1++;
                    }
                    break;

                case 49:
                    Logger.LogOnce("[1] 데이터 저장");
                    InsertData(lbBarcode1.Text, lbLPartNo1.Text,
                               lbReclFwdMeasure1.Text, CheckLabelStatus(lbReclFwdMeasure1),
                               lbReclBwdMeasure1.Text, CheckLabelStatus(lbReclBwdMeasure1),
                               lbLeverMeasure1.Text, CheckLabelStatus(lbLeverMeasure1),
                               lbFwdDiffMeasure1.Text, lbBwdDiffMeasure1.Text,
                               lbTotalDiffMeasure1.Text, CheckLabelStatus(lbTotalDiffMeasure1));
                    wStep1++;
                    break;

                case 50:

                    if (lbReclFwdMeasure1.BackColor == System.Drawing.Color.Blue &&
                        lbReclBwdMeasure1.BackColor == System.Drawing.Color.Blue &&
                        lbLeverMeasure1.BackColor == System.Drawing.Color.Blue &&
                        lbTotalDiffMeasure1.BackColor == System.Drawing.Color.Blue)
                    {
                        PlaySound("DINGDONG.wav");
                        BarcodePrint1();
                        Logger.LogOnce("[1] 바코드 출력");
                        CloseMeasureLog1();
                        GlobalValues.OkCount++;
                        GlobalValues.TotalCount++;
                        lbOkCount.Text = GlobalValues.OkCount.ToString();
                        lbNGCount.Text = (GlobalValues.TotalCount - GlobalValues.OkCount).ToString();
                        lbTotalCount.Text = GlobalValues.TotalCount.ToString();
                        GlobalValues.SaveCounts();
                    }
                    else
                    {
                        CloseMeasureLog1();
                        BarcodePrintNg1();
                        PlaySound("NG.wav");
                        GlobalValues.TotalCount++;
                        lbOkCount.Text = GlobalValues.OkCount.ToString();
                        lbNGCount.Text = (GlobalValues.TotalCount - GlobalValues.OkCount).ToString();
                        lbTotalCount.Text = GlobalValues.TotalCount.ToString();
                        GlobalValues.SaveCounts();
                    }
                    wStep1 = 51;
                    break;

                case 51:
                    if (tmrWatch1.ElapsedMilliseconds > 1000)
                    {
                        wStep1 = 0;
                        _lever41Delay1 = false;
                        _alarmRetryCount1 = 0;
                        _alarmAtStep1 = 0;
                    }
                    break;

                case 99: // 서보 알람 3회 초과 정지 — 리셋 전까지 대기
                    break;

            }

        }

        double tmpNum1, tmpNum2;

        private void workTimer2_Tick(object sender, EventArgs e)
        {
            lbStep2.Text = $"[{wStep2.ToString()}][{wRstStep2.ToString()}]";

            if (PLCData2.PlcValueBit[0, 1] == true && wRstStep2 == 0) //리셋 스위치
            {
                wRstStep2 = 0.1;
            }

            // reset
            switch (wRstStep2)
            {
                case 0:
                    break;

                case 0.1:
                    wStep2 = 0;
                    _lever41Delay2 = false;
                    _alarmRetryCount2 = 0;
                    _alarmAtStep2 = 0;
                    tmrRstWatch2.Restart();
                    wRstStep2 = 0.2;
                    break;

                case 0.2:
                    if (PLCData2.PlcValueBit[0, 1] == true)
                    {
                        if (tmrRstWatch2.ElapsedMilliseconds > 1000)
                        {
                            PLCData2.FlagRecvAll = true;
                            Logger.LogOnce("[2] 리셋 조건 발동");
                            wRstStep2 = 1;
                        }
                    }
                    else
                    {
                        wRstStep2 = 0;
                    }
                    break;

                case 1: //모든 시그널 클리어
                    for (int word = 0; word <= 7; word++)
                    {
                        for (int bit = 0; bit <= 15; bit++)
                        {
                            PLCData2.SetPlcBit(word, bit, false);
                        }
                    }
                    for (int bit = 0; bit <= 15; bit++)
                    {
                        PLCData2.SetPlcBit(9, bit, false);
                    }
                    for (int bit = 0; bit <= 15; bit++)
                    {
                        PLCData2.SetPlcBit(11, bit, false);
                    }
                    for (int bit = 0; bit <= 15; bit++)
                    {
                        PLCData2.SetPlcBit(12, bit, false);
                    }
                    for (int bit = 0; bit <= 15; bit++)
                    {
                        PLCData2.SetPlcBit(13, bit, false);
                    }
                    wRstStep2++;
                    break;

                case 2:
                    PLCData2.SetPlcBit(9, 1, false);
                    PLCData2.SetPlcBit(9, 2, false);
                    PLCData2.SetPlcBit(4, 8, true); //클램프 상승 지령 D4004.8
                    PLCData2.SetPlcBit(4, 10, true); //클램프 후진
                    PLCData2.SetPlcBit(4, 12, true); //LVDT 후진 지령 D4004.12
                    tmrWatch2.Restart();
                    wRstStep2++;
                    break;

                case 3:

                    if (PLCData2.PlcValueBit[0, 6] == true)
                    {
                        PLCData2.SetPlcBit(4, 8, false); //클램프 상승 지령 D4004.8
                    }
                    if (PLCData2.PlcValueBit[0, 9] == true)
                    {
                        PLCData2.SetPlcBit(4, 10, false); //클램프 후진 D4000.9
                    }
                    if (PLCData2.PlcValueBit[0, 10] == true)
                    {
                        PLCData2.SetPlcBit(4, 12, false); //LVDT 후진 지령 D4004.12 D4000.10
                    }

                    if (PLCData2.PlcValueBit[0, 6] == true &&
                        PLCData2.PlcValueBit[0, 9] == true &&
                        PLCData2.PlcValueBit[0, 10] == true)
                    {
                        tmrWatch2.Stop();
                        wRstStep2++;
                    }
                    break;

                case 4:
                    PLCData2.SetPlcBit(9, 9, true); //1축 서보 온
                    PLCData2.SetPlcBit(11, 9, true);//2축 서보 온
                    PLCData2.SetPlcBit(9, 3, true); //1축 알람 리셋
                    PLCData2.SetPlcBit(11, 3, true);//2축 알람 리셋
                    PLCData2.SetPlcBit(9, 6, true); //1축 수동 ON
                    PLCData2.SetPlcBit(11, 6, true);//2축 수동 ON                 
                    PLCData2.SetPlcBit(9, 5, false); //1축 자동 OFF
                    PLCData2.SetPlcBit(11, 5, false);//2축 자동 OFF                    
                    wRstStep2++;
                    break;

                case 5:
                    //신호 확인
                    if (PLCData2.PlcValueBit[8, 1] == false && PLCData2.PlcValueBit[10, 1] == false &&
                        PLCData2.PlcValueBit[8, 7] == true && PLCData2.PlcValueBit[10, 7] == true &&
                        PLCData2.PlcValueBit[8, 4] == true && PLCData2.PlcValueBit[10, 4] == true)
                    {
                        wRstStep2++;
                    }
                    break;

                case 6:

                    PLCData2.SetPlcBit(9, 1, true); //1축 CCW
                    PLCData2.SetPlcBit(11, 1, true);//2축 CCW
                    tmrWatch2.Restart();
                    PLCData2.Servo1JogSpd = 1000;
                    PLCData2.ServoSet();
                    wRstStep2++;
                    break;

                case 7:

                    if (tmrWatch2.ElapsedMilliseconds > 1000)
                    {
                        PLCData2.SetPlcBit(9, 1, false); //1축 CCW
                        PLCData2.SetPlcBit(11, 1, false);//2축 CCW
                        tmrWatch2.Stop();
                        wRstStep2++;
                    }
                    break;

                case 8:

                    if (PLCData2.PlcValueBit[9, 1] == false && PLCData2.PlcValueBit[11, 1] == false)
                    {
                        PLCData2.SetPlcBit(9, 4, true); //1축 홈 ON 
                        tmrWatch2.Restart();
                        wRstStep2 = 8.1;
                    }
                    break;

                case 8.1:

                    if (tmrWatch2.ElapsedMilliseconds > 500)
                    {
                        tmrWatch2.Stop();
                        PLCData2.SetPlcBit(9, 4, false); //1축 홈 OFF                                          
                        wRstStep2 = 9;
                    }
                    break;


                case 9:
                    if (PLCData2.PlcValueBit[8, 12] == true) // 1축 홈포지션 완료
                    {
                        PLCData2.SetPlcBit(9, 4, false); //1축 홈 OFF
                        tmrRstWatch2.Restart();
                        wRstStep2 = 9.1;
                    }
                    break;

                case 9.1:
                    if (tmrRstWatch2.ElapsedMilliseconds > 500)
                    {
                        tmrRstWatch2.Stop();
                        wRstStep2 = 10;
                    }
                    break;

                case 10:

                    PLCData2.SetPlcBit(11, 4, true); //2축 홈 ON
                    tmrRstWatch2.Restart();
                    wRstStep2 = 10.1;
                    break;

                case 10.1:

                    if (tmrRstWatch2.ElapsedMilliseconds > 500)
                    {
                        PLCData2.SetPlcBit(11, 4, false); //2축 홈 OFF
                        tmrRstWatch2.Stop();
                        wRstStep2 = 11;
                    }
                    break;

                case 11:
                    if (PLCData2.PlcValueBit[10, 12] == true) // 2축 홈포지션 완료
                    {
                        PLCData2.SetPlcBit(11, 4, false); //2축 홈 OFF
                        tmrRstWatch2.Restart();
                        wRstStep2 = 11.1;
                    }
                    break;

                case 11.1:

                    if (tmrRstWatch2.ElapsedMilliseconds > 1500)
                    {
                        wRstStep2 = 12;
                    }
                    break;

                case 12:

                    PLCData2.SetPlcBit(9, 6, false); //1축 수동 OFF
                    PLCData2.SetPlcBit(11, 6, false); //2축 수동 OFF
                    PLCData2.SetPlcBit(9, 5, true); //1축 자동 ON
                    PLCData2.SetPlcBit(11, 5, true); //1축 자동 ON
                    wRstStep2++;
                    break;

                case 13:
                    if (PLCData2.PlcValueBit[8, 3] == true && PLCData2.PlcValueBit[10, 3] == true) //자동 
                    {
                        PLCData2.SetPlcBit(12, 0, true); //1축 1번 포지션ㄱㄱ
                        wRstStep2++;
                    }
                    break;

                case 14:
                    if (PLCData2.PlcValueBit[14, 0] == true && PLCData2.PlcValueBit[12, 0] == true) //1축 1번 완료 AND 명령 동시 ON
                    {
                        PLCData2.SetPlcBit(12, 0, false);
                        wRstStep2++;
                    }
                    break;

                case 15:
                    PLCData2.SetPlcBit(13, 0, true); //2축 1번 포지션ㄱㄱ
                    wRstStep2++;
                    break;

                case 16:
                    if (PLCData2.PlcValueBit[15, 0] == true && PLCData2.PlcValueBit[13, 0] == true) //2축 1번 완료 AND 명령 동시 ON
                    {
                        PLCData2.SetPlcBit(13, 0, false);
                        wRstStep2++;
                    }
                    break;

                case 17:
                    InitControl2();
                    PLCData2.FlagRecvAll = false;
                    wRstStep2 = 0;
                    Logger.LogOnce("[2] 리셋 완료");
                    break;

            }

            // work
            switch (wStep2)
            {
                case 0:

                    if (MeasureData2.TargetScan == "0")
                    {
                        if (PLCData2.PlcValueBit[0, 0] == true) //작업 시작
                        {
                            Logger.LogOnce("[2] 작업 시작(바코드 미사용)");
                            string tmppart = lbLPartNo2.Text;
                            string tmpbarcode = lbBarcode2.Text;
                            InitControl2();
                            lbLPartNo2.Text = tmppart;
                            lbBarcode2.Text = tmpbarcode;
                            lbReclFwdSpec2.Text = $"{MeasureData2.ReclineForwardTorqueMin.ToString()} ~ {MeasureData2.ReclineForwardTorqueMax.ToString()} Nm";
                            lbReclBwdSpec2.Text = $"{MeasureData2.ReclineForwardTorqueMin.ToString()} ~ {MeasureData2.ReclineForwardTorqueMax.ToString()} Nm";
                            lbLeverSpec2.Text = $"{MeasureData2.LeverTorqueMin.ToString()} ~ {MeasureData2.LeverTorqueMax.ToString()} Nm";

                            DiffSpec2.Text = $"{MeasureData2.SpecDiff.ToString()}";

                            PLCData2.SetPlcBit(4, 9, true); //클램프 하강 지령 D4004.9
                            Logger.LogOnce("[2] 클램프 하강 시작");
                            tmrWatch2.Restart();
                            PLCData2.FlagRecvAll = false;
                            wStep2++;
                        }
                    }
                    else
                    {
                        if (PLCData2.PlcValueBit[0, 0] == true && lbLPartNo2.Text != "" && lbBarcode2.BackColor == System.Drawing.Color.Blue) //작업 시작
                        {
                            Logger.LogOnce("[2] 작업 시작(바코드 사용)");
                            string tmppart = lbLPartNo2.Text;
                            string tmpbarcode = lbBarcode2.Text;
                            InitControl2();
                            lbLPartNo2.Text = tmppart;
                            lbBarcode2.Text = tmpbarcode;
                            lbReclFwdSpec2.Text = $"{MeasureData2.ReclineForwardTorqueMin.ToString()} ~ {MeasureData2.ReclineForwardTorqueMax.ToString()} Nm";
                            lbReclBwdSpec2.Text = $"{MeasureData2.ReclineForwardTorqueMin.ToString()} ~ {MeasureData2.ReclineForwardTorqueMax.ToString()} Nm";
                            lbLeverSpec2.Text = $"{MeasureData2.LeverTorqueMin.ToString()} ~ {MeasureData2.LeverTorqueMax.ToString()} Nm";

                            DiffSpec2.Text = $"{MeasureData2.SpecDiff.ToString()}";

                            PLCData2.SetPlcBit(4, 9, true); //클램프 하강 지령 D4004.9
                            Logger.LogOnce("[2] 클램프 하강 시작");
                            tmrWatch2.Restart();
                            PLCData2.FlagRecvAll = false;
                            wStep2++;
                        }
                    }
                    break;

                case 1:
                    if (PLCData2.PlcValueBit[0, 7] == true)
                    {
                        PLCData2.SetPlcBit(4, 9, false); //클램프 하강 지령 D4004.9
                        PLCData2.SetPlcBit(4, 11, true); //클램프 전진
                        wStep2++;
                    }
                    break;

                case 2:
                    if (PLCData2.PlcValueBit[0, 8] == true) //클램프 전진 완료 D4000.8
                    {
                        PLCData2.SetPlcBit(4, 11, false);
                        tmrWatch2.Restart();
                        wStep2++;
                    }
                    break;

                case 3:
                    ResetLeverTq2();
                    ResetReclTq2();
                    wStep2++;
                    tmrWatch2.Restart();
                    break;

                case 4:
                    if (tmrWatch2.ElapsedMilliseconds > 1000)
                    {
                        tmrWatch2.Stop();
                        wStep2++;
                    }
                    break;

                case 5:
                    StartMeasureLog2();
                    PLCData2.SetPlcBit(13, 1, true); //2축 2 포지션 이동 레버해제
                    Logger.LogOnce("[2] 2축 2번 포지션 이동 시작");
                    measureStartTime2 = DateTime.Now;
                    timeList2.Clear();
                    valueList2.Clear();
                    tmrWatch2.Restart();
                    tmpMax2 = 0;
                    _csv2.Clear();
                    wStep2++;
                    break;

                case 6:

                    double elapsedSeconds = tmrWatch2.Elapsed.TotalSeconds;

                    if (tmpMax2 < MeasureData2.ValueLeverTq * MeasureData2.LeverTorqueTolerance) tmpMax2 = MeasureData2.ValueLeverTq * MeasureData2.LeverTorqueTolerance; //최대값 갱신                                                                   
                    ClassZedGraph.DrawGraph(PlotLever2, MeasureData2.ValueLeverTq * MeasureData2.LeverTorqueTolerance, elapsedSeconds);

                    _csv2.Add(elapsedSeconds, MeasureData2.ValueLeverTq * MeasureData2.LeverTorqueTolerance);

                    if (PLCData2.PlcValueBit[15, 1] == true && PLCData2.PlcValueBit[13, 1] == true) //2축 2 포지션 완료 AND 명령 동시 ON
                    {
                        tmpsave2 = DateTime.Now.ToString("yyMMddHHmmss") + Lot2 + lbLPartNo2.Text;
                        _csv2.Save($"{tmpsave2}_Lever_Torque");
                        lbLeverMeasure2.Text = tmpMax2.ToString("F1");
                        WriteMeasureLabelLog2("lbLeverMeasure2", $"ValueLeverTq={MeasureData2.ValueLeverTq:F4}, LeverTorqueTolerance={MeasureData2.LeverTorqueTolerance:F4}", "tmpMax2 = Max(ValueLeverTq * LeverTorqueTolerance)", tmpMax2.ToString("F1"));
                        PLCData2.SetPlcBit(13, 1, false);
                        wStep2++;
                    }
                    break;

                case 7:
                    JudgeAndSetLabel(MeasureData2.LeverTorqueMin, MeasureData2.LeverTorqueMax, tmpMax2, lbLeverMeasure2);
                    WriteMeasureLabelLog2("lbLeverMeasure2(Judge)", $"tmpMax2={tmpMax2:F4}, Min={MeasureData2.LeverTorqueMin}, Max={MeasureData2.LeverTorqueMax}", "합격/불합격 판정", lbLeverMeasure2.Text);
                    wStep2++;
                    break;

                case 8:
                    if (MeasureData2.BurnishingCount > 0)
                    {
                        bCount2 = 0;
                        wStep2 = 8.1;
                    }
                    else
                    {
                        wStep2++;
                    }
                    break;

                case 8.1: //버니싱
                    PLCData2.SetPlcBit(12, 3, true);//1축 4 포지션
                    wStep2 = 8.2;
                    break;

                case 8.2:
                    if (PLCData2.PlcValueBit[14, 3] == true && PLCData2.PlcValueBit[12, 3] == true) //완료 AND 명령 동시 ON
                    {
                        PLCData2.SetPlcBit(12, 3, false);
                        wStep2 = 8.3;
                    }
                    break;

                case 8.3:
                    PLCData2.SetPlcBit(12, 4, true);//1축 5 포지션
                    wStep2 = 8.4;
                    break;

                case 8.4:
                    if (PLCData2.PlcValueBit[14, 4] == true && PLCData2.PlcValueBit[12, 4] == true) //완료 AND 명령 동시 ON
                    {
                        PLCData2.SetPlcBit(12, 4, false);
                        wStep2 = 8.5;
                    }
                    break;

                case 8.5:
                    bCount2++;
                    if (bCount2 >= MeasureData2.BurnishingCount)
                    {
                        wStep2 = 9;
                    }
                    else
                    {
                        wStep2 = 8.1; //다시 버니싱
                    }
                    break;

                case 9: // 토크 리셋
                    ResetReclTq2();
                    tmrWatch2.Restart();
                    wStep2++;
                    break;

                case 10:
                    if (tmrWatch2.ElapsedMilliseconds > 1000)
                    {
                        tmrWatch2.Stop();
                        wStep2++;
                    }
                    break;

                case 11:
                    PLCData2.SetPlcBit(12, 1, true); //1축 2포지션 이동 
                    measureStartTime2 = DateTime.Now;
                    timeList2.Clear();
                    valueList2.Clear();
                    tmrWatch2.Restart();
                    tmpMax2 = 0;
                    _csv2.Clear();
                    wStep2++;
                    break;

                case 12:

                    //89A3B-SW510
                    //89A3B-SW520
                    elapsedSeconds = tmrWatch2.Elapsed.TotalSeconds;
                    double tol = MeasureData2.ReclineFwdTorqueTolerance;

                    if (elapsedSeconds > 1)
                    {
                        if (tmpMax2 < Math.Abs(MeasureData2.ValueReclTq) * tol) tmpMax2 = Math.Abs(MeasureData2.ValueReclTq) * tol; //최대값 갱신 
                        ClassZedGraph.DrawGraph(PlotReclFwd2, Math.Abs(MeasureData2.ValueReclTq) * tol, elapsedSeconds);
                    }

                    _csv2.Add(elapsedSeconds, Math.Abs(MeasureData2.ValueReclTq) * tol);


                    if (PLCData2.PlcValueBit[14, 1] == true && PLCData2.PlcValueBit[12, 1] == true) //1축 2 포지션 완료 AND 명령 동시 ON
                    {
                        lbReclFwdMeasure2.Text = tmpMax2.ToString("F1");
                        WriteMeasureLabelLog2("lbReclFwdMeasure2", $"ValueReclTq={MeasureData2.ValueReclTq:F4}, ReclineFwdTorqueTolerance={MeasureData2.ReclineFwdTorqueTolerance:F4}", "tmpMax2 = Max(Abs(ValueReclTq) * Tol)", tmpMax2.ToString("F1"));
                        PLCData2.SetPlcBit(12, 1, false);
                        wStep2++;
                    }
                    break;

                case 13:
                    _csv2.Save($"{tmpsave2}_Fwd_Torque");
                    JudgeAndSetLabel(MeasureData2.ReclineForwardTorqueMin, MeasureData2.ReclineForwardTorqueMax, tmpMax2, lbReclFwdMeasure2);
                    WriteMeasureLabelLog2("lbReclFwdMeasure2(Judge)", $"tmpMax2={tmpMax2:F4}, Min={MeasureData2.ReclineForwardTorqueMin}, Max={MeasureData2.ReclineForwardTorqueMax}", "합격/불합격 판정", lbReclFwdMeasure2.Text);
                    wStep2++;
                    break;

                case 14:
                    PLCData2.SetPlcBit(12, 2, true); //1축 3포지션 이동 
                    measureStartTime2 = DateTime.Now;
                    timeList2.Clear();
                    valueList2.Clear();
                    tmrWatch2.Restart();
                    tmpMax2 = 0;
                    wStep2++;
                    _csv2.Clear();
                    break;

                case 15:

                    elapsedSeconds = tmrWatch2.Elapsed.TotalSeconds;
                    tol = MeasureData2.ReclineBwdTorqueTolerance;

                    if (elapsedSeconds > 1)
                    {
                        if (tmpMax2 < Math.Abs(MeasureData2.ValueReclTq) * tol) tmpMax2 = Math.Abs(MeasureData2.ValueReclTq) * tol; //최대값 갱신 
                        ClassZedGraph.DrawGraph(PlotReclBwd2, Math.Abs(MeasureData2.ValueReclTq) * tol, elapsedSeconds);
                    }
                    _csv2.Add(elapsedSeconds, Math.Abs(MeasureData2.ValueReclTq) * tol);

                    if (PLCData2.PlcValueBit[14, 2] == true && PLCData2.PlcValueBit[12, 2] == true) //1축 3포지션 완료 AND 명령 동시 ON
                    {
                        lbReclBwdMeasure2.Text = tmpMax2.ToString("F1");
                        WriteMeasureLabelLog2("lbReclBwdMeasure2", $"ValueReclTq={MeasureData2.ValueReclTq:F4}, ReclineBwdTorqueTolerance={MeasureData2.ReclineBwdTorqueTolerance:F4}", "tmpMax2 = Max(Abs(ValueReclTq) * Tol)", tmpMax2.ToString("F1"));
                        PLCData2.SetPlcBit(12, 2, false);
                        wStep2++;
                    }
                    break;

                case 16:
                    _csv2.Save($"{tmpsave2}_Bwd_Torque");
                    JudgeAndSetLabel(MeasureData2.ReclineBackwardTorqueMin, MeasureData2.ReclineBackwardTorqueMax, tmpMax2, lbReclBwdMeasure2);
                    WriteMeasureLabelLog2("lbReclBwdMeasure2(Judge)", $"tmpMax2={tmpMax2:F4}, Min={MeasureData2.ReclineBackwardTorqueMin}, Max={MeasureData2.ReclineBackwardTorqueMax}", "합격/불합격 판정", lbReclBwdMeasure2.Text);
                    wStep2++;
                    break;


                case 17:
                    Logger.LogOnce("[2] 1축 1번 포지션 이동 시작");
                    PLCData2.SetPlcBit(13, 0, true); //2축 1번 포지션 이동 레버해제                    
                    wStep2++;
                    break;

                case 18:
                    if (PLCData2.PlcValueBit[15, 0] == true && PLCData2.PlcValueBit[13, 0] == true) //2축 1번 완료 AND 명령 동시 ON
                    {
                        PLCData2.SetPlcBit(13, 0, false);
                        wStep2++;
                    }
                    break;

                case 19: //LVDT 전진
                    PLCData2.SetPlcBit(4, 13, true); //LVDT 전진 지령 D4004.13
                    tmrWatch2.Restart();
                    wStep2++;
                    break;

                case 20:
                    if (tmrWatch2.ElapsedMilliseconds > 2000 ||
                        PLCData2.PlcValueBit[0, 11] == true ||  // LVDT 전진
                        PLCData2.PlcValueBit[0, 12] == true ||  // 가이드 전진 1
                        PLCData2.PlcValueBit[0, 14] == true ||  // 가이드 전진 1
                        PLCData2.PlcValueBit[0, 15] == true)    // 가이드 전진 2
                    {
                        PLCData2.SetPlcBit(4, 13, false); //LVDT 전진 지령 OFF D4004.13
                        tmrWatch2.Stop();
                        wStep2++;
                    }
                    break;

                case 21:
                    ResetReclTq2();
                    tmrWatch2.Restart();
                    wStep2++;
                    break;

                case 22:
                    if (tmrWatch2.ElapsedMilliseconds > 1000)
                    {
                        DiffStartTmp2_1 = MeasureData2.ValueLvdt;
                        StartDebugLog2(); // 디버그 로그 시작
                        WriteDebugLog2(22, "LVDT_BASE_SET");
                        tmrWatch2.Stop();
                        wStep2++;
                    }
                    break;

                case 23:

                    tmpBeforeSpeed2 = PLCData2.Servo1JogSpd;
                    PLCData2.FlagRecvAll = true;
                    PLCData2.Servo1JogSpd = PLCData2.DiffSpeed;
                    PLCData2.ServoSet();
                    wStep2++;
                    break;

                case 23.1:

                    if (PLCData2.PlcValue[5002] == PLCData2.DiffSpeed)
                    {
                        PLCData2.FlagRecvAll = false;
                        wStep2 = 24;
                    }
                    break;

                case 24:
                    PLCData2.SetPlcBit(9, 5, false); //1축 자동 OFF
                    PLCData2.SetPlcBit(11, 5, false); //2축 자동 OFF
                    PLCData2.SetPlcBit(9, 6, true); //1축 수동 ON
                    PLCData2.SetPlcBit(11, 6, true); //2축 수동 ON
                    wStep2++;
                    break;

                case 25:
                    if (PLCData2.PlcValueBit[8, 4] == true && PLCData2.PlcValueBit[10, 4] == true) //수동 확인
                    {
                        timeList2.Clear();
                        valueList2.Clear();
                        DiffFwdTmp2 = 0;
                        DiffBwdTmp2 = 0;
                        wStep2++;
                    }
                    break;

                case 26:
                    StartDiffLog2(); // 유격 로그 시작
                    WriteDiffLog2(26, "CCW_START"); // 시작 로그
                    WriteDebugLog2(26, "CCW_START");
                    PLCData2.SetPlcBit(9, 2, true); //1축 CCW ON
                    WriteDiffLog2(26, "PLC_CCW_ON");
                    tmrWatch2.Restart();
                    _csv2.Clear();

                    // 루프용 좌표 초기화
                    diff2HasFirstPoint = false;
                    diff2RedStartCaptured = false;
                    MaxDiffBwd2 = 0; // CCW(후진) 최대 변위 초기화

                    wStep2++;
                    break;

                case 27:

                    // tmpNum2 = 10 / MeasureData2.DiffLimit; // 원본 - 10까지 정규화
                    // tmpNum2 = 10 / MeasureData2.DiffLimitBwd; // CCW(후진)이므로 DiffLimitBwd 사용
                    tmpNum2 = MeasureData2.DiffTorqueCorrection; // 유격 토크 보정계수 (전/후진 통합)

                    ClassZedGraph.DrawGraphLine(PlotDiff2, MeasureData2.ValueLvdt - DiffStartTmp2_1, tmpNum2 * -1 * (MeasureData2.ValueReclTq), 0);
                    _csv2.Add(MeasureData2.ValueLvdt - DiffStartTmp2_1, tmpNum2 * -1 * MeasureData2.ValueReclTq);

                    diff2LastX = MeasureData2.ValueLvdt - DiffStartTmp2_1;
                    diff2LastY = tmpNum2 * -1 * MeasureData2.ValueReclTq;

                    // 루프용 좌표 기록
                    if (!diff2HasFirstPoint)
                    {
                        diff2FirstX = MeasureData2.ValueLvdt - DiffStartTmp2_1;
                        diff2FirstY = tmpNum2 * -1 * (MeasureData2.ValueReclTq);
                        diff2HasFirstPoint = true;
                    }

                    // 최대 변위값 추적 (CCW 후진)
                    double currentDiff2 = Math.Abs(MeasureData2.ValueLvdt - DiffStartTmp2_1);
                    if (currentDiff2 > MaxDiffBwd2)
                    {
                        MaxDiffBwd2 = currentDiff2;
                    }

                    WriteDiffLog2(27, "CCW_MEASURE"); // 측정 로그
                    WriteDebugLog2(27, "CCW_MEASURE", MeasureData2.ValueLvdt - DiffStartTmp2_1, tmpNum2 * -1 * MeasureData2.ValueReclTq);

                    // CCW 완료: 토크 > DiffLimitBwd (단, DiffLimitBwd<=0이면 SpecDiff 변위 도달 시 완료)
                    bool ccwComplete2 = (MeasureData2.DiffLimitBwd > 0 && Math.Abs(MeasureData2.ValueReclTq) > MeasureData2.DiffLimitBwd)
                        || (MeasureData2.DiffLimitBwd <= 0 && currentDiff2 >= MeasureData2.SpecDiff);
                    if (ccwComplete2 && tmrWatch2.Elapsed.TotalSeconds > 1)
                    {
                        WriteDebugLog2(27, "CCW_END", diff2LastX, diff2LastY);
                        WriteDiffLog2(27, "CCW_END"); // CCW 종료 로그
                        //Logger.LogOnce($"[2][CCW CONDITION][{Math.Abs(MeasureData2.ValueReclTq).ToString()}]");
                        diff2BlackEndX = diff2LastX;
                        diff2BlackEndY = diff2LastY;

                        PLCData2.SetPlcBit(9, 2, false); //1축 CCW OFF
                        WriteDiffLog2(27, "PLC_CCW_OFF");
                        // PLCData2.SetPlcBit(9, 7, true); //1축 수동 정지 지령 - 마지막(case 37.7)에만 사용
                        wStep2++;
                        tmrWatch2.Restart();
                    }
                    break;

                case 28:
                    if (tmrWatch2.ElapsedMilliseconds > 1000)
                    {
                        lbBwdDiff2.Text = MaxDiffBwd2.ToString("F2"); // CCW(후진) 최대 변위 표시
                        WriteMeasureLabelLog2("lbBwdDiff2", "ValueLvdt, DiffStartTmp2_1, currentDiff2", "MaxDiffBwd2 = Max(currentDiff2) CCW 최대변위(mm)", MaxDiffBwd2.ToString("F2"));
                        wStep2++;
                    }
                    break;

                case 29: // 서보 알람 뜨면
                    if (PLCData2.PlcValueBit[8, 1] == true || PLCData2.PlcValueBit[10, 1] == true)
                    {
                        if (_alarmRetryCount2 >= 3)
                        {
                            Logger.LogOnce("[2] 서보 알람 3회 초과", "[2] 서보 알람 3회 초과 — step 29(유격 측정 중 서보 알람)에서 정지. 설비 점검 필요.");
                            wStep2 = 99;
                        }
                        else
                        {
                            _alarmAtStep2 = 29;
                            _alarmRetryCount2++;
                            PLCData2.SetPlcBit(9, 7, false); //1축 알람 리셋
                            PLCData2.SetPlcBit(9, 3, true); //1축 알람 리셋
                            PLCData2.SetPlcBit(11, 3, true); //2축 알람 리셋
                            tmrWatch2.Restart();
                            wStep2++;
                        }
                    }
                    else
                    {
                        wStep2 = 32;
                    }
                    break;

                case 30: // 서보 알람 뜨면
                    if (tmrWatch2.ElapsedMilliseconds > 1000)
                    {
                        tmrWatch2.Stop();
                        PLCData2.SetPlcBit(9, 3, false); //1축 알람 리셋
                        PLCData2.SetPlcBit(11, 3, false); //2축 알람 리셋
                        wStep2++;
                    }
                    break;

                case 31:
                    if (PLCData2.PlcValueBit[8, 1] == false && PLCData2.PlcValueBit[10, 1] == false)
                    {
                        _alarmRetryCount2 = 0; // 복구 성공 시 재시도 카운트 리셋
                        wStep2++;
                    }
                    else
                    {
                        if (_alarmRetryCount2 > 3)
                        {
                            Logger.LogOnce("[2] 서보 알람 3회 초과", "[2] 서보 알람 3회 초과 — step 29(유격 측정 중 서보 알람)에서 정지. 설비 점검 필요.");
                            wStep2 = 99;
                        }
                        else
                            wStep2 = 29;
                    }
                    break;

                case 32:
                    timeList2.Clear();
                    valueList2.Clear();
                    PLCData2.SetPlcBit(9, 5, false); //1축 자동 OFF
                    PLCData2.SetPlcBit(11, 5, false); //2축 자동 OFF
                    PLCData2.SetPlcBit(9, 6, true); //1축 수동 ON
                    PLCData2.SetPlcBit(11, 6, true); //2축 수동 ON
                    wStep2++;
