                    MaxDiffFwd2 = 0; // CW(전진) 최대 변위 초기화
                    wStep2 = 34.1;
                    break;

                case 34.1:
                    {
                        // 매 타이머마다 빨강 선 그리기 (토크 방향 전환 구간 곡선 표현)
                        // 방안2: CCW 끝점에서 이어지도록 X 좌표 계산
                        // X = diff2BlackEndX + (현재LVDT - CW시작LVDT)
                        double yVal341_2 = tmpNum2 * -1 * (MeasureData2.ValueReclTq);
                        // Y값이 범위를 넘으면 범위 내로 클램핑 (보정)
                        double yMax341_2 = MeasureData2.DiffGraphYMax;
                        if (yVal341_2 > yMax341_2) yVal341_2 = yMax341_2;
                        else if (yVal341_2 < -yMax341_2) yVal341_2 = -yMax341_2;
                        ClassZedGraph.DrawGraphLine(PlotDiff2, diff2BlackEndX + (MeasureData2.ValueLvdt - diff2CwStartLvdt), yVal341_2, 1);
                        WriteDiffLog2(34.1, "TRANSITION"); // 전환 구간 로그
                        WriteDebugLog2(34.1, "TRANSITION", diff2BlackEndX + (MeasureData2.ValueLvdt - diff2CwStartLvdt), yVal341_2);
                    }
                    // 토크가 양수로 바뀌면 본격 측정 시작
                    if ((MeasureData2.ValueReclTq) > 0)
                    {
                        WriteDiffLog2(34.1, "TORQUE_POSITIVE"); // 토크 양수 전환 로그

                        DiffStartTmp2_2 = MeasureData2.ValueLvdt;

                        // CW 시작점 기록 (루프 닫기용)
                        if (!diff2RedStartCaptured)
                        {
                            diff2RedStartX = MeasureData2.ValueLvdt - DiffStartTmp2_1;
                            diff2RedStartY = tmpNum2 * -1 * (MeasureData2.ValueReclTq);
                            diff2RedStartCaptured = true;
                        }

                        tmrWatch2.Restart();
                        wStep2 = 35;
                    }
                    break;

                case 35:
                    {
                        // 방안2: CCW 끝점에서 이어지도록 X 좌표 계산
                        // X = diff2BlackEndX + (현재LVDT - CW시작LVDT)
                        double x = diff2BlackEndX + (MeasureData2.ValueLvdt - diff2CwStartLvdt); // 방안2 적용
                        double y = tmpNum2 * -1 * MeasureData2.ValueReclTq;               // Nm

                        // Y값이 범위를 넘으면 범위 내로 클램핑 (보정)
                        double yMax35_2 = MeasureData2.DiffGraphYMax;
                        double yGraph = y;
                        if (yGraph > yMax35_2) yGraph = yMax35_2;
                        else if (yGraph < -yMax35_2) yGraph = -yMax35_2;
                        ClassZedGraph.DrawGraphLine(PlotDiff2, x, yGraph, 1);
                        _csv2.Add(x, y); // CSV에는 원본값 저장

                        diff2LastX = x;
                    diff2LastY = y;

                    // 루프용 마지막 점 갱신
                    if (!diff2HasFirstPoint)
                    {
                        diff2FirstX = x;
                        diff2FirstY = y;
                        diff2HasFirstPoint = true;
                    }

                    // 최대 변위값 추적 (CW 전진)
                    double currentDiffFwd2 = Math.Abs(MeasureData2.ValueLvdt - DiffStartTmp2_2);
                    if (currentDiffFwd2 > MaxDiffFwd2)
                    {
                        MaxDiffFwd2 = currentDiffFwd2;
                    }

                    WriteDiffLog2(35, "CW_MEASURE"); // CW 측정 로그
                    WriteDebugLog2(35, "CW_MEASURE", x, yGraph);

                    // CW 완료: 토크 > DiffLimitFwd (단, DiffLimitFwd<=0이면 SpecDiff 변위 도달 시 완료)
                    bool cwComplete2 = (MeasureData2.DiffLimitFwd > 0 && Math.Abs(MeasureData2.ValueReclTq) > MeasureData2.DiffLimitFwd)
                        || (MeasureData2.DiffLimitFwd <= 0 && currentDiffFwd2 >= MeasureData2.SpecDiff);
                    if (cwComplete2 && tmrWatch2.Elapsed.TotalSeconds > 1)
                    {
