                }
            }

            Plc2RequestReadyPlc = true;
        }
        private void Plc2ParsePlcResponse(string response, int startAddress)
        {
            try
            {
                // 제어 문자 제거 (ACK, ETX)
                response = response.Replace(((char)6).ToString(), "").Replace(((char)3).ToString(), "");

                int startIndex = response.IndexOf("00RSB");
                if (startIndex == -1)
                {
                    Logger.LogOnce("[경고] '00RSB' 없음");
                    return;
                }

                // 데이터 시작 위치
                int dataStart = startIndex + 9; // "00RSB06%" 이후부터
                int dataLength = response.Length - dataStart;
                int wordCount = dataLength / 4;

                for (int i = 0; i < wordCount; i++)
                {
                    int addr = startAddress + i;
                    string hex = response.Substring(dataStart + (i * 4), 4);
                    ushort word = Convert.ToUInt16(hex, 16);

                    if (addr >= 4000 && addr <= 4031)
                    {
                        // D4000~4031 → 비트로 저장
                        int wordIndex = addr - 4000;
                        for (int bit = 0; bit < 16; bit++)
                        {
                            PLCData2.PlcValueBit[wordIndex, bit] = ((word >> bit) & 1) == 1;
                        }
                    }
                    else
                    {
                        // 병합 대상인 경우
                        if (i + 1 < wordCount)
                        {
                            string hexLow = response.Substring(dataStart + (i * 4), 4);       // 하위
                            string hexHigh = response.Substring(dataStart + ((i + 1) * 4), 4); // 상위

                            string hex32 = hexHigh + hexLow; // 상 + 하
                            int value32 = Convert.ToInt32(hex32, 16);

                            PLCData2.PlcValue[addr] = value32;
                            PLCData2.PlcValue[addr + 1] = 0; // 상위 워드는 무시
                            //Logger.LogOnce($"[32비트 병합] D{addr}/{addr + 1} → {value32}");
                            i++; // 2워드 소비
                            continue;
                        }
                        else
                        {
                            Logger.LogOnce("[경고] D병합 실패 워드 부족", $"[경고] D{addr} 병합 실패: 워드 부족");
                            break;
                        }
                    }

                }
            }
            catch (Exception ex)
            {
                Logger.LogOnce("[에러] 파싱 실패", "[에러] 파싱 실패: " + ex.Message);
            }
        }

