        private readonly StringBuilder _rxBufLvdt1 = new StringBuilder(256);
        private readonly StringBuilder _rxBufLvdt2 = new StringBuilder(256);
        private System.Timers.Timer _recallTimer;
        private DateTime _lastRecallLog1 = DateTime.MinValue;
        private DateTime _lastRecallLog2 = DateTime.MinValue;
        // LVDT 진단 로그 한 번만 출력 (종류·포트별)
        private bool _lvdtLogSent1, _lvdtLogSent2;
        private bool _lvdtLogRx1, _lvdtLogRx2;
        private bool _lvdtLogOk1, _lvdtLogOk2;
        private bool _lvdtLogAlarm1, _lvdtLogAlarm2;
        private bool _lvdtLogFormat1, _lvdtLogFormat2;
        private bool _lvdtLogParseFail1, _lvdtLogParseFail2;
        private bool _lvdtLogEx1, _lvdtLogEx2;

        private void InitSerial(SerialPort sp)
        {
            sp.NewLine = "\r";
            sp.ReadTimeout = 50;
            sp.WriteTimeout = 50;
            sp.ReceivedBytesThreshold = 1;
        }

        private void StartRecallPolling()
        {
            if (_recallTimer != null) return;
            _recallTimer = new System.Timers.Timer(100); // 10 Hz 시도
            _recallTimer.AutoReset = true;
            _recallTimer.Elapsed += OnRecallTimerElapsed;
            _recallTimer.Start();
        }

        private void OnRecallTimerElapsed(object sender, System.Timers.ElapsedEventArgs e)
        {
            TrySendRecall(SerialLvdt1);
            TrySendRecall(SerialLvdt2);
        }

        private void TrySendRecall(SerialPort sp)
        {
            if (sp == null || !sp.IsOpen) return;
            if (sp.BytesToWrite == 0)
            {
                // LT30 매뉴얼: 1ch 현재값 요청 명령 "r" + CR LF (기존 "\rRECALL\r" 아님)
                sp.Write("r\r\n");
                if (ReferenceEquals(sp, SerialLvdt1) && !_lvdtLogSent1)
                {
                    _lvdtLogSent1 = true;
                    Logger.LogOnce($"[LVDT 진단] r (LT30) 전송됨: {sp.PortName}");
                }
                else if (ReferenceEquals(sp, SerialLvdt2) && !_lvdtLogSent2)
                {
                    _lvdtLogSent2 = true;
                    Logger.LogOnce($"[LVDT 진단] r (LT30) 전송됨: {sp.PortName}");
                }
            }
        }

        private void SerialLvdt_DataReceived(object sender, SerialDataReceivedEventArgs e)
        {
            var sp = sender as SerialPort;
            if (sp == null) return;

            try
            {
                string chunk = sp.ReadExisting();
                if (string.IsNullOrEmpty(chunk)) return;

                bool is1 = ReferenceEquals(sp, SerialLvdt1);
                if (is1 && !_lvdtLogRx1) { _lvdtLogRx1 = true; string logChunk = chunk.Replace("\r", "\\r").Replace("\n", "\\n"); Logger.LogOnce($"[LVDT 진단] 수신 {sp.PortName}: [{logChunk}] (길이:{chunk.Length})"); }
                else if (!is1 && !_lvdtLogRx2) { _lvdtLogRx2 = true; string logChunk = chunk.Replace("\r", "\\r").Replace("\n", "\\n"); Logger.LogOnce($"[LVDT 진단] 수신 {sp.PortName}: [{logChunk}] (길이:{chunk.Length})"); }

                StringBuilder buf = is1 ? _rxBufLvdt1 : _rxBufLvdt2;
                buf.Append(chunk);

                ParseFrames(sp, buf);
            }
            catch (Exception ex)
            {
                if (ReferenceEquals(sp, SerialLvdt1) && !_lvdtLogEx1) { _lvdtLogEx1 = true; Logger.LogOnce($"[LVDT 진단] DataReceived 예외 {sp?.PortName}: {ex.Message}"); }
                else if (ReferenceEquals(sp, SerialLvdt2) && !_lvdtLogEx2) { _lvdtLogEx2 = true; Logger.LogOnce($"[LVDT 진단] DataReceived 예외 {sp?.PortName}: {ex.Message}"); }
            }
        }
        private void ParseFrames(SerialPort sp, StringBuilder buf)
        {
            int lineEndIndex;
            int removeLen;
            while (IndexOfCrOrLf(buf, out lineEndIndex, out removeLen))
            {
                string frame = buf.ToString(0, lineEndIndex);
                buf.Remove(0, removeLen);

                if (string.IsNullOrWhiteSpace(frame)) continue;

                frame = frame.Trim();
                if (frame.Length > 0 && frame[0] == '\u0005')
                    frame = frame.TrimStart('\u0005').Trim();

                // LT30 알람 응답: AE / BE 등은 숫자 파싱 스킵
                if (frame.Length >= 2 && (frame.StartsWith("AE", StringComparison.Ordinal) || frame.StartsWith("BE", StringComparison.Ordinal)))
                {
                    if (ReferenceEquals(sp, SerialLvdt1) && !_lvdtLogAlarm1) { _lvdtLogAlarm1 = true; Logger.LogOnce($"[LVDT 진단] 알람 응답 스킵 {sp.PortName}: frame=[{frame}]"); }
                    else if (ReferenceEquals(sp, SerialLvdt2) && !_lvdtLogAlarm2) { _lvdtLogAlarm2 = true; Logger.LogOnce($"[LVDT 진단] 알람 응답 스킵 {sp.PortName}: frame=[{frame}]"); }
                    continue;
                }

                // LT30 형식: "A + 12.3456" / "B - 0.1234" / "AN + 12.3456" (모드정보 포함) — 채널 A/B, 이후 숫자 추출
                if (frame.Length < 2 || (frame[0] != 'A' && frame[0] != 'B'))
                {
                    if (ReferenceEquals(sp, SerialLvdt1) && !_lvdtLogFormat1) { _lvdtLogFormat1 = true; Logger.LogOnce($"[LVDT 진단] LT30 형식 아님: frame=[{frame}]"); }
                    else if (ReferenceEquals(sp, SerialLvdt2) && !_lvdtLogFormat2) { _lvdtLogFormat2 = true; Logger.LogOnce($"[LVDT 진단] LT30 형식 아님: frame=[{frame}]"); }
                    continue;
                }

                // 숫자 부분 추출: "A + 12.3456", "AN + 12.3456", "A+2.1888" 등 모두 처리
                Match numMatch = Regex.Match(frame, @"[+-]?[\d.]+");
                string valueStr = numMatch.Success ? numMatch.Value : frame.Substring(1).Trim().Replace(" ", "");
                if (!double.TryParse(valueStr, NumberStyles.Any, CultureInfo.InvariantCulture, out double val))
                {
                    if (ReferenceEquals(sp, SerialLvdt1) && !_lvdtLogParseFail1) { _lvdtLogParseFail1 = true; Logger.LogOnce($"[LVDT 진단] 값 파싱실패: '{valueStr}' (frame=[{frame}])"); }
                    else if (ReferenceEquals(sp, SerialLvdt2) && !_lvdtLogParseFail2) { _lvdtLogParseFail2 = true; Logger.LogOnce($"[LVDT 진단] 값 파싱실패: '{valueStr}' (frame=[{frame}])"); }
                    continue;
                }

                if (ReferenceEquals(sp, SerialLvdt1) && !_lvdtLogOk1) { _lvdtLogOk1 = true; Logger.LogOnce($"[LVDT 진단] OK: ValueLvdt={val}, {sp.PortName}"); }
                else if (ReferenceEquals(sp, SerialLvdt2) && !_lvdtLogOk2) { _lvdtLogOk2 = true; Logger.LogOnce($"[LVDT 진단] OK: ValueLvdt={val}, {sp.PortName}"); }

                if (ReferenceEquals(sp, SerialLvdt1))
                {
                    MeasureData1.ValueLvdt = val;
                    this.Invoke((MethodInvoker)(() => { if (srcLvdt1 != null) srcLvdt1.Text = $"{val:F4}"; }));
                }
                else if (ReferenceEquals(sp, SerialLvdt2))
                {
                    MeasureData2.ValueLvdt = val;
                    this.Invoke((MethodInvoker)(() => { if (srcLvdt2 != null) srcLvdt2.Text = $"{val:F4}"; }));
                }
            }
        }

        /// <summary>버퍼에서 CR 또는 LF(또는 CRLF) 위치 반환. LT30 응답은 CR LF 종료.</summary>
        private static bool IndexOfCrOrLf(StringBuilder sb, out int lineEndIndex, out int removeLength)
        {
            lineEndIndex = -1;
            removeLength = 0;
            for (int i = 0; i < sb.Length; i++)
            {
                if (sb[i] == '\r')
                {
                    lineEndIndex = i;
                    removeLength = (i + 1 < sb.Length && sb[i + 1] == '\n') ? 2 : 1;
                    return true;
                }
                if (sb[i] == '\n')
                {
                    lineEndIndex = i;
                    removeLength = 1;
                    return true;
                }
            }
            return false;
        }

