        private void InitPlot(ScottPlot.WinForms.FormsPlot plotControl, string xLabel, string yLabel,
                      double xMin, double xMax, double yMin, double yMax, double specMin, double specMax)
        {
            plotControl.Reset();
            var plt = plotControl.Plot;

            plt.Axes.Bottom.Label.Text = xLabel;
            plt.Axes.Left.Label.Text = yLabel;
            plt.Axes.SetLimitsX(xMin, xMax);
            plt.Axes.SetLimitsY(yMin, yMax);
            plt.Clear();

            var specLine1 = plt.Add.HorizontalLine(specMin);
            specLine1.LineStyle.Pattern = ScottPlot.LinePattern.Solid;
            specLine1.LineStyle.Width = 2;
            specLine1.LineStyle.Color = new ScottPlot.Color(255, 0, 0); // 빨간색

            var specLine2 = plt.Add.HorizontalLine(specMax);
            specLine2.LineStyle.Pattern = ScottPlot.LinePattern.Solid;
            specLine2.LineStyle.Width = 2;
            specLine2.LineStyle.Color = new ScottPlot.Color(255, 0, 0); // 빨간색

            plotControl.Refresh();
        }

